(window.WISE_WORLD_Q = window.WISE_WORLD_Q || {}).ru = [
  { id:1, topic:"Наука о мытье рук", emoji:"🧼",
    question:"Когда на руках есть микробы или вирусы, вызывающие болезни, почему мыть их с « мылом » намного безопаснее, чем мыть одной водой?",
    choices:["Форма мыльных пузырей пугает микробов и прогоняет их далеко","Мыло способно полностью разрушить жировую плёнку (наружную оболочку), которая окутывает вирус, и растворить её","Мыло делает кожу рук твёрдой, как железо, и отталкивает микробов","Запах мыла мешает микробам дышать"],
    answerIndex:1,
    explanation:"Поверхность многих микробов и вирусов (например, гриппа) на самом деле защищена тонкой жировой плёнкой, которая называется « липид ». Именно эта плёнка даёт им силу вторгаться в тело человека. Жир никогда не смыть одной водой, но молекулы мыла умеют окружать жир и растворять его в воде. Когда ты с силой трёшь руки мылом, жировая плёнка, защищающая вирус, мгновенно растворяется в клочья, вирус уже не может оставаться живым и полностью уничтожается. Мытьё с мылом не просто смывает микробов с рук — это сильнейшее « лекарство », которое научно истребляет врага." },
  { id:2, topic:"Прямое давление", emoji:"🩹",
    question:"Когда от глубокой раны кровь хлещет потоком, какое « правильное первое действие (прямое давление) » нужно сделать в самую первую очередь, чтобы спасти жизнь?",
    choices:["Всё время мягко поглаживать рану тканью, смоченной водой","Приложить чистую ткань прямо к ране и сильно давить сверху, навалившись всем телом","Резко размахивать раной, пока кровь не остановится","Облепить рану грязью, чтобы остановить кровь"],
    answerIndex:1,
    explanation:"Потерять много крови — самая большая опасность: кислород перестаёт поступать к клеткам, и жизнь можно потерять в считаные мгновения. Всемирная основа медицины, которая это предотвращает, — « прямое давление ». Сильно прижимая разорванный сосуд снаружи, ты физически закрываешь путь, по которому течёт кровь. Кроме того, нажимая, ты помогаешь « тромбоцитам » крови — команде, которая строит корочку, — собраться у раны и заделать прорванную дырку. Если вытирать слабо и кое-как, кровь не остановить. Мудрость сильного давления двумя руками удерживает чью-то жизнь." },
  { id:3, topic:"Шина при переломе", emoji:"🦴",
    question:"Когда после падения подозревают « перелом кости ноги или руки », почему это место ни в коем случае нельзя силой заставлять двигаться?",
    choices:["От движения кость вдруг превратится в круглый шар","Острый конец сломанной кости может изрезать важные мышцы, сосуды и нервы под кожей и вызвать сильное кровотечение или паралич","От движения кость станет в десять раз тяжелее","Кость испугается и исчезнет из тела"],
    answerIndex:1,
    explanation:"Когда кость с хрустом ломается под кожей, сломанный конец очень острый и колкий, как осколок стекла. Если ты силой заставишь это место двигаться, гадая « смогу ли я идти? », этот острый костяной нож начнёт двигаться внутри одежды и мышц, разрежет толстый соседний сосуд и вызовет внутреннее кровотечение или повредит нерв и вызовет паралич, который никогда не заживёт. При подозрении на перелом приложи ветку или твёрдую доску (шину) и одновременно закрепи сустав выше и сустав ниже места перелома, чтобы оно не сдвинулось ни на миллиметр, пока ждёшь помощи. Это и есть верная мудрость первой помощи." },
  { id:4, topic:"Помощь при ожоге", emoji:"🔥",
    question:"Когда коснулся огня или кипятка и получил ожог, что нужно сделать самым первым, очень спеша, прежде всего?",
    choices:["Намазать рану маслом или грязью, чтобы она не сохла","Охлаждать рану чистой холодной водой не меньше 15 минут, пока боль не утихнет","Аккуратно содрать обожжённую кожу ногтями","Завернуть в тёплую ткань, чтобы сохранить тепло"],
    answerIndex:1,
    explanation:"Страшное в ожоге то, что даже после того, как ты убрал руку от горячего предмета, огромная тепловая энергия, оставшаяся на поверхности кожи, продолжает, как тлеющий уголь, просачиваться глубже в кожу (в дерму и мышечный слой) и разрушать клетки. Остановить это можно только одним способом — как можно быстрее отнять это тепло холодной водой. Охлаждение дольше 15 минут останавливает волну тепла, идущую вглубь, и делает рану как можно более поверхностной. Если раннего охлаждения мало, кожа глубоко отмирает, остаётся большой шрам на всю жизнь, и микробам легче проникнуть. Охлаждать водой — это научный « тормоз » против распространения ожога." },
  { id:5, topic:"Раствор для питья", emoji:"🥤",
    question:"Когда сильный понос или рвота высушили тело, почему с научной точки зрения лучше пить воду, смешанную с небольшим количеством « соли » и « сахара » (раствор для питья), чем простую воду?",
    choices:["Если смешать соль и сахар, вода станет вкусной и поднимет настроение","В стенке тонкого кишечника есть особая дверь, которая впитывает воду с огромной скоростью, когда соль (натрий) и сахар (глюкоза) приходят вместе","Соль напрямую сжигает и убивает микробов поноса","Если выпить сахар, живот мгновенно замёрзнет и понос остановится"],
    answerIndex:1,
    explanation:"При сильном поносе или рвоте стенка кишечника повреждена, поэтому даже простая вода плохо впитывается и выходит с другого конца. Но в стенке тонкого кишечника человека есть дверь (SGLT-1): когда натрий и глюкоза приходят вместе в соотношении 1 к 2, она мгновенно, как мощный насос, всасывает воду в клетки. На этом основан « раствор для питья », спасший много жизней по всему миру. Эта волшебная вода, сделанная из половины чайной ложки соли и четырёх с половиной столовых ложек сахара на один литр воды, может надёжно спасти жизнь от обезвоживания даже там, где нет капельницы. Это мудрость медицины." },
  { id:6, topic:"Память иммунитета", emoji:"💉",
    question:"Стоит человеку переболеть некоторой сильной болезнью, например корью, как он почти не заболевает ею снова. Как называется эта замечательная система внутри тела?",
    choices:["Омоложение костей","Система памяти иммунитета","Кристаллизация крови","Иллюзия мозга"],
    answerIndex:1,
    explanation:"Внутри нашего тела команда иммунитета, включая « лейкоциты », что бьются с микробами и вирусами, патрулирует круглые сутки. Когда злой вирус вторгается впервые, на создание оружия (антитела) против него уходит много дней, и за это время можно тяжело заболеть. Но удивительно в команде иммунитета то, что она полностью запоминает « облик и приметы » врага, с которым однажды билась, и хранит их в мозге и клетках. Спустя годы, когда тот же враг вторгается снова, она по этой памяти мгновенно создаёт огромное количество точного оружия и одним ударом уничтожает его, прежде чем ты заболеешь. Технология, использующая это, — безопасно посадить лишь память до болезни — это « вакцина (прививка) »." },
  { id:7, topic:"Если укусил зверь", emoji:"🐕",
    question:"Когда тебя укусил дикий пёс, лиса, летучая мышь или другой зверь, даже если рана кажется маленькой, почему нужно срочно промыть её обильной водой с мылом — это вопрос жизни и смерти?",
    choices:["Цвет с зубов зверя может перейти на твою кожу","В слюне зверя может прятаться страшный вирус, как бешенство, который разрушает мозг и убивает почти 100% заражённых","Если не промыть, на месте укуса вырастет новая шерсть","Чтобы выразить зверю свою благодарность"],
    answerIndex:1,
    explanation:"По всему миру есть страшная болезнь под названием « бешенство », которая передаётся людям, когда их кусает зверь — носитель вируса. Если этот вирус попадает в тело и по нервам доходит до мозга, то, как только появляются признаки, даже современная медицина почти никогда не спасает человека, и он умирает. Однако есть короткий запас времени, прежде чем вирус из раны войдёт в нервы. Сразу после укуса, яростно промывая рану обильной чистой проточной водой с мылом дольше 15 минут, ты физически смываешь и уменьшаешь прилипший к ране вирус и можешь не дать ему дойти до мозга. Если укусил зверь — « прежде всего сильно промой »: это абсолютное правило медицины, что решает жизнь или смерть." },
  { id:8, topic:"Ядовитые существа", emoji:"🐍",
    question:"Когда ядовитая змея, паук или другое опасное существо укусило руку или ногу, какое « неправильное действие » нельзя совершать ни в коем случае?",
    choices:["Не двигать местом укуса и тихо лечь","Запаниковать, громко кричать и в спешке бегать кругом, спасаясь","Сказать взрослому рядом, какое именно существо тебя укусило","Держать рану ниже сердца"],
    answerIndex:1,
    explanation:"Когда тебя укусило ядовитое существо, если ты в страхе паникуешь, бегаешь кругом или шумишь, биение сердца (пульс) резко учащается. Тогда яд, попавший в рану, едет на быстро текущей крови и мгновенно расходится по мышцам, мозгу и органам всего тела, так что яд распространяется куда быстрее, и ты можешь потерять жизнь. Если укусило что-то ядовитое, правильно — успокоить сердце, не бежать, не двигаться и тихо, неподвижно лежать. Держа рану чуть ниже сердца, ты замедляешь скорость, с какой кровь с ядом возвращается к сердцу. Сохранять спокойствие и неподвижность — это и есть щит, тормозящий распространение яда." },
  { id:9, topic:"Пот и соль", emoji:"💦",
    question:"В жаркий день после обильного пота, почему пить залпом только большое количество « чистой воды без соли » на самом деле ухудшает самочувствие?",
    choices:["От чистой воды вода в желудке протухнет","Так как с потом из тела теряется и соль (натрий), питьё одной воды слишком сильно разбавляет уровень соли в крови, и мозг и мышцы не работают как надо (низкий натрий)","От слишком большого количества воды растворятся все кости тела","Чистая вода меняет твою кровь с красной на синюю"],
    answerIndex:1,
    explanation:"Жидкости тела (например, кровь) всегда содержат около 0,9% « соли », и благодаря этому точному уровню приказы нервов верно доходят до мышц и мозга. Когда сильно потеешь, эта важная соль вытекает вместе с водой. Если потом влить в это опустевшее тело только чистую воду без соли, уровень соли внутри станет ещё ниже. Тогда мозг решает « если ещё разбавится — опасно! » и отказывается от воды или пытается выбросить её с потом и мочой. В итоге ноги сильно сводит судорогой (тепловые судороги), появляются головная боль и головокружение. Восполняя жидкость в жаркий день, нужно всегда брать вместе совсем немного соли." },
  { id:10, topic:"Открыть дыхательный путь", emoji:"😮",
    question:"Когда человек упал без сознания и, возможно, не дышит, в чём настоящая цель положения « поднять подбородок вверх и запрокинуть голову назад (открыть дыхательный путь) »?",
    choices:["Повернуть лицо вверх, чтобы солнечный свет попадал в глаза","При потере сознания большая мышца в глубине горла (корень языка) обвисает вниз и полностью перекрывает путь воздуха; это предотвращает удушье","Выпрямить кости шеи, чтобы человек стал выше","Помочь упавшему человеку крепче уснуть"],
    answerIndex:1,
    explanation:"Когда человек теряет сознание и совсем обмякает, мышца « языка » в глубине горла тоже вяло западает назад. Это называют « западением языка ». Горло лежащего на спине человека полностью закрывается — путь воздуха (дыхательный путь) перекрыт собственным языком, поэтому он не может дышать и задыхается. Чтобы это предотвратить, прижимая лоб, другой рукой крепко подними кость подбородка к небу. Это физически широко раскрывает пространство в глубине горла, и воздух свободно доходит до лёгких. Это « открытие дыхательного пути » — всемирный первый шаг спасения жизни, до искусственного дыхания или сжатий грудной клетки." },
  { id:11, topic:"Как работает дыхание", emoji:"💨",
    question:"Когда мы вдыхаем и выдыхаем, почему тело должно выбрасывать газ под названием « углекислый газ »?",
    choices:["Если углекислый газ накопится в теле, кожа станет зелёной","Углекислый газ — ядовитый отход, который образуется, когда клетки сжигают питательные вещества, чтобы бодро работать, и если он копится в крови, кровь становится кислой и угрожает жизни","Если не выдыхать углекислый газ, тело раздуется, как шар, и взлетит в небо","Чтобы держать тело внутри холодным"],
    answerIndex:1,
    explanation:"Как машина сжигает бензин и выпускает выхлоп, так и триллионы клеток человека сжигают питательные вещества пищи с помощью кислорода, чтобы создать энергию жизни, и всегда создают выхлопной отход — « углекислый газ ». Когда много этого газа растворяется в крови, у него есть ядовитая сила быстро менять кровь из нейтральной в опасную « кислую ». Когда кровь становится кислой, клетки мозга и сердца уже не могут работать, и человек умирает. Именно поэтому сердце спешно гонит кровь к лёгким, на секунду раньше выбрасывает углекислый газ при дыхании и вместо него берёт свежий кислород — снова и снова." },
  { id:12, topic:"Что делает сердце", emoji:"❤️",
    question:"В чём настоящая цель того, что « сердце » в левой части груди бьётся без отдыха, ни на секунду, с рождения до смерти?",
    choices:["Растирать и измельчать пищу в желудке","Гонять по кругу « грузовик тела », который везёт кровь, полную кислорода и питательных веществ, к клеткам всего тела и собирает отходы (как углекислый газ), что выделяют клетки","Выталкивать наружу лишнюю воду, скопившуюся в теле","Разносить эхом свой звук, чтобы сообщать друзьям, где ты"],
    answerIndex:1,
    explanation:"Сердце — очень мощный мышечный насос, который двигает « кровь », текущую по нашему телу. Кровь несёт кислород, полученный в лёгких, и питательные вещества, впитанные в кишечнике, и доставляет их клеткам от макушки до кончиков пальцев ног — она играет роль важного курьера. Если сердце замрёт, ток крови полностью остановится. Тогда клетки мозга, которым нужно особенно много кислорода, всего за несколько минут испытывают его нехватку, получают необратимые разрушительные повреждения и умирают. То, что сердце продолжает биться, — важнейшая система жизнеобеспечения, доставляющая « паёк для жизни » клеткам всего тела." },
  { id:13, topic:"Спасти тонущего", emoji:"🆘",
    question:"Ты заметил друга или человека, который тонет в реке или море. Чтобы защитить себя, помогая ему, что « ни в коем случае нельзя делать »?",
    choices:["Громко крикнуть взрослым вокруг: « Кто-нибудь, сюда! Человек тонет! » и позвать на помощь","Решив, что сможешь доплыть и спасти, прыгнуть прямо в воду с пустыми руками, чтобы схватить тонущего","Бросить на воду верёвку, длинную палку или пустую пластиковую бутылку (вместо поплавка)","Протянуть руку с твёрдой земли рядом"],
    answerIndex:1,
    explanation:"Тонущий человек, который не может дышать, полностью в панике от страха смерти. Если человек подплывёт, чтобы помочь, тонущий с невероятной, свирепой силой цепляется за тебя сверху, чтобы использовать как поплавок, и заталкивает тебя под воду. Когда так случается, даже взрослый, хороший пловец, тонет вместе с ним на дно, и трагедия, когда тонут оба, повторяется по всему миру без конца. Если человек тонет, тебе самому абсолютно запрещено лезть в воду. Кричи громко с безопасного места на суше и брось всё, что « плавает », — пустую бутылку, кусок дерева, — чтобы он ухватился. Это и есть верный кодекс выживания." },
  { id:14, topic:"Профилактика столбняка", emoji:"🔩",
    question:"Когда наступил на старый ржавый гвоздь или получил глубокую рану от старого инструмента в земле, почему нельзя терять бдительность даже спустя дни, когда рана уже закрылась?",
    choices:["Ржавое железо превратится в магнит у тебя под кожей","Микроб под названием столбнячная палочка любит места без кислорода (воздуха), может размножаться в глубине раны и выделять страшный яд, что сводит судорогой все мышцы тела","Если оставить глубокую рану, через годы нога станет короче","Из старой раны вырастают новые ногти"],
    answerIndex:1,
    explanation:"В земле и старом ржавом железе прячутся споры (как яйца) микроба, вызывающего « столбняк ». Главная особенность этого микроба в том, что он « анаэробный »: ненавидит касаться воздуха. Поэтому, в отличие от мелкой поверхностной раны, его любимое место — глубина раны, куда не доходит воздух, как от глубокого укола гвоздём. После того как рана закрылась, микроб взрывообразно размножается в темноте под кожей и выделяет мощный яд, разрушающий нервы человека. Через дни–недели приходит страшная болезнь, при которой рот уже не открывается или все мышцы выгибаются назад и дышать становится невозможно. При глубокой ране нужно иметь мудрость обратиться в больницу насчёт лечения столбняка." },
  { id:15, topic:"Сильный свет и глаза", emoji:"👁️",
    question:"После того как прямо смотрел на « сильный свет » — солнце или яркие искры сварки, — почему центр зрения продолжает мерцать так, что не видно, даже если закрыть глаза?",
    choices:["Сильный свет испарил все слёзы в глазах","Клетки важнейшего экрана в глубине глаза, который ловит свет (сетчатки), получили большое повреждение, похожее на ожог, от избытка энергии, и нервы в панике","Частицы света заперлись в глазу и буянят там","Мозг вспоминает цвет света"],
    answerIndex:1,
    explanation:"В глубине глаза человека есть очень нежный нервный экран — « сетчатка », которая превращает входящий свет в электрические сигналы и шлёт их в мозг. В солнечном и очень сильном свете содержится энергия с огромной разрушительной силой, например « ультрафиолет ». Если смотреть на это прямо невооружённым глазом, на твоей сетчатке происходит то же, что когда лупа собирает солнечный свет и прожигает бумагу. Мерцание — доказательство того, что клетки кричат, потому что повреждены. Если это сильно, в центре сетчатки появляется дырка (солнечная ретинопатия), что ведёт к слепоте, когда зрение не возвращается. Отвести глаза от сильного света за одну секунду — научное правило их защиты." },
  { id:16, topic:"Зубы взрослого", emoji:"🦷",
    question:"Почему нельзя допускать, чтобы взрослые зубы (« постоянные зубы »), что вырастают примерно в старших классах начальной школы, испортились кариесом — причина на всю жизнь?",
    choices:["Если у взрослого зуба кариес, все кости головы расшатаются","В отличие от молочных, когда постоянный зуб портится кариесом и выпадает, новый снизу уже никогда не вырастет — это часть тела на всю жизнь","Потеря взрослого зуба означает, что ты совсем не сможешь говорить","Зуб с кариесом начинает двигаться сам по себе среди ночи"],
    answerIndex:1,
    explanation:"Детские зубы (молочные) сменяются, даже если в них кариес, ведь новые взрослые зубы подталкивают снизу. Но « постоянные зубы », что вырастают около 10 лет, буквально, — окончательная версия, сделанная служить до самого конца жизни. В отличие от хвоста ящерицы или человеческой кожи, твёрдая эмаль на поверхности зуба, однажды разрушенная и растворённая, на 100% никогда не восстановится в прежний вид своими силами. Потеряв зубы, ты уже не можешь измельчать пищу, что сильно вредит желудку и кишечнику, ухудшает питание всего тела и сокращает жизнь. Бережно хранить взрослые зубы — значит самому обеспечивать своё будущее здоровье." },
  { id:17, topic:"Защита мозга", emoji:"🚭",
    question:"По всему миру закон строго запрещает детям и подросткам вводить в тело « алкоголь », « табак » или опасные наркотики, что расстраивают мозг. В чём научная причина?",
    choices:["Эти вещи — привилегия взрослых, чтобы наслаждаться в одиночку","Тело ребёнка до примерно 20 лет всё ещё на полной скорости строит мозговые цепи (сеть), и если входит яд, развитие полностью останавливается, а память и контроль над чувствами ломаются навсегда","Если дети это употребляют, цвет всей одежды становится чёрным","Настоящей причины нет; это просто правило, которое взрослые придумали, чтобы ограничивать детей"],
    answerIndex:1,
    explanation:"Человеческий мозг с рождения до примерно 20 лет долго, изо дня в день, ведёт работы по прокладке сложных сетей нервных клеток, чтобы стать умнее и лучше владеть чувствами. Если в этот очень нежный период « в разгар стройки » в мозг втекают яды — алкоголь, никотин табака или наркотики вроде конопли, — проводка разрушается в хаос, и рост полностью останавливается. В итоге даже взрослым ты уже не можешь думать глубоко, срываешься и устраиваешь насилие или становишься жалким телом, что не может жить без наркотика (зависимость). Чтобы защитить мозг, держи твёрдую решимость всю жизнь не приближаться к этим ядам." },
  { id:18, topic:"Сон чистит мозг", emoji:"😴",
    question:"Когда живёшь каждый день, не высыпаясь как следует, почему люди становятся более склонны болеть и не могут ясно думать?",
    choices:["Если не спать, кости тела становятся всё легче и ломаются","Система очистки, что вымывает вредные отходы из мозга, и гормон роста, что залечивает раны тела, — работающие только во сне, — перестают работать (глимфатическая система)","Если пропустишь сон, солнце разозлится и даст жар","Если человек не спит, за 3 дня он полностью превращается в робота"],
    answerIndex:1,
    explanation:"Днём, пока мы живём, работая головой, клетки мозга выделяют много вредных белковых отходов, например « бета-амилоид », которые копятся в голове. Когда человек ночью входит в глубокий сон, клетки мозга чуть сжимаются, создавая зазоры, и в эти зазоры, как цунами, втекает чистая вода — « спинномозговая жидкость », — и начинается большая уборка, разом вымывающая дневные отходы. Это система очистки мозга, открытая недавней медициной. Если часто недосыпать, ядовитые отходы остаются грудой в голове, нервы гибнут, ты становишься раздражительным, иммунитет падает, и ты проигрываешь всякой болезни. Сон — лучшее моющее средство для мозга." },
  { id:19, topic:"Как работает наследственность", emoji:"🧬",
    question:"Во всех странах мира и на протяжении истории есть правило против брака и рождения детей с очень близкими кровными родственниками (отец и дочь, брат и сестра). В чём общая научная (генетическая) причина?",
    choices:["С близкими родственниками невозможно решить, как назвать будущего ребёнка","Каждый где-то в генах несёт небольшую ошибку чертежа (причину болезни), и у близких родственников одинаковые ошибки накладываются, поэтому вероятность ребёнка с тяжёлой болезнью или инвалидностью резко взлетает","С близкими родственниками внутри дома становится тесно","Богу не нравится такая внешность"],
    answerIndex:1,
    explanation:"Гены — чертёж тела человека — образуются, когда получают набор из двух томов: половину от отца и половину от матери. Каждый тайно несёт несколько « серьёзных ошибок чертежа » где-то в одном томе, но если чертёж другого тома исправен, можно жить здоровым, не болея. Однако люди, близкие по крови, наследуют чертежи от совершенно одних предков, поэтому « места их ошибок » очень схожи. Когда у этих двоих рождается ребёнок, « чертёж с багом ровно в том же месте » от отца и от матери складывается вдвойне, ошибку уже нечем прикрыть, и рождается малыш с тяжёлой болезнью или инвалидностью. Из опыта и мудрости человечество создало правило, чтобы избегать этого риска." },
  { id:20, topic:"Переливание и группы", emoji:"🩸",
    question:"Почему нельзя по собственному, неумелому суждению вливать свою « кровь » прямо уколом в тело тяжелораненого, чтобы поделиться ею (переливание)?",
    choices:["Если войдёт чужая кровь, цвет твоих волос станет таким же, как у него","У крови есть группы (A, B, O, AB), и если смешать разные типы, эритроциты яростно отвергают друг друга внутри тела, слипаются, закупоривают сосуды и убивают человека","Если поделиться кровью, твой вес уменьшится вдвое","От чужой крови болит живот"],
    answerIndex:1,
    explanation:"Вся кровь выглядит одинаковой красной жидкостью, но на поверхности эритроцитов есть « антигены » — особые метки (ключи и печати), что показывают тип этой крови. Это группа крови (система ABO). Например, если по ошибке влить кровь типа B в тело человека типа A, команда иммунитета типа A впадает в панику — « вторгся враг, какого я не видел! » — и разом нападает на все входящие эритроциты типа B, спутывая их в плотный комок, как сеть (реакция склеивания). Сгусток закупоривает толстые сосуды лёгких и мозга и мгновенно вызывает смерть от шока. В медицине анализ, проверяющий группу крови, — проверка жизни, которую нельзя пропускать." },
  { id:21, topic:"Хорошо жевать", emoji:"🍽️",
    question:"Когда кладёшь пищу в рот, почему хорошо жевать зубами (более 30 раз) перед глотанием так сильно помогает работе желудка и кишечника?",
    choices:["Если хорошо жевать, пища полностью исчезает во рту","Измельчение пищи на маленькие кусочки во много раз увеличивает общую « площадь поверхности », поэтому пищеварительные соки кишечника быстро пропитывают её целиком и эффективно впитывают питательные вещества","Жевание поднимает температуру в желудке до 100 градусов","Тренировка зубов делает мышцы подошв ног сильнее"],
    answerIndex:1,
    explanation:"Это прекрасное применение математической идеи « площади поверхности ». Если бросить в желудок большой кусок картофеля как есть, желудочный сок (кислота пищеварения) может растворять его лишь с поверхности, поэтому до середины уходят часы, желудок устаёт и расстраивается. Но если зубами разжевать его в мелкую крошку, один большой кусок делится на тысячи крошечных. От деления « суммарная площадь », где пища может касаться пищеварительных соков, расширяется взрывообразно. Благодаря этому, едва она доходит до желудка и кишечника, соки мгновенно пропитывают её до середины, растворяют в кашицу и впитывают 100% питательных веществ для жизни, не оставляя ничего. Хорошо жевать — это самая первая кухонная фабрика, до кишечника." },
  { id:22, topic:"Подавился (спасение)", emoji:"🍖",
    question:"Когда большой кусок пищи застрял в горле и человек задыхается, ты обнимаешь его сзади и сильно толкаешь вверх по животу (приём Геймлиха). В чём настоящая цель давления на живот?",
    choices:["Вдавить живот, чтобы человек выглядел стройнее","Сильное давление на живот толкает вверх воздух, ещё оставшийся в лёгких, и этим давлением воздуха (силой воздушного ружья) с силой выбивает предмет, застрявший в горле","Чтобы напугать червей в животе","Чтобы силой протолкнуть застрявшую пищу вниз, в желудок"],
    answerIndex:1,
    explanation:"Когда что-то застряло в горле и человек не может дышать, на деле в « лёгких » ещё полно невыдохнутого воздуха. Между грудью и животом человека есть большой мышечный « пол » — « диафрагма », что надувает и сжимает лёгкие. Когда обнимаешь сзади и сильно толкаешь вверх чуть выше пупка, органы живота поднимаются вверх, и в свою очередь диафрагма « бах! » сильно сжимает лёгкие снизу. Тогда воздух, оставшийся в лёгких, мгновенно, как яростная буря, устремляется обратно к горлу и, точно воздушное ружьё, выбивает наружу кусок пищи, что закупорил горло. Это прекрасный, основанный на физике приём спасения, использующий устройство человеческого тела." },
  { id:23, topic:"Паразиты и сырое", emoji:"🐛",
    question:"Почему нельзя есть сырое мясо диких животных или пить сырую речную воду без нагрева — страшная причина о червях, что плодятся внутри тела?",
    choices:["От сырого тело человека превращается в животное","Внутри тел существ и в сырой воде таятся паразиты, спрятанные как невидимые яйца, что входят в кишечник человека, кусают стенку и крадут питание или пожирают органы","Сырая вода превращает все кости живота в кашу","От сырого мяса в животе раздаются крики животных"],
    answerIndex:1,
    explanation:"Речная вода в природе и мясо диких оленей, кабанов или свиней почти на 100% таят яйца и личинки крошечных невидимых « паразитов » (как ленточные черви и аскариды). Если съесть их сырыми, они выживают даже в кислоте желудка и доходят до кишечника. Там яйца вылупляются, и длинные вырастают в огромных червей в несколько метров, что присасываются к стенке кишечника и высасывают все питательные вещества, что ты съел ради жизни, оставляя тебя истощённым. Некоторые забираются в мозг или печень и растворяют органы в кашу — злобные черви, угрожающие жизни. Паразиты очень слабы перед огнём (жаром), поэтому нужна мудрость гигиены: прожаривай мясо до середины и кипяти воду, чтобы уничтожить их всех." },
  { id:24, topic:"Допить лекарство", emoji:"💊",
    question:"Когда принимаешь « антибиотики », что врач дал, чтобы убить микробов в теле, какое страшное правило медицины нужно непременно соблюдать?",
    choices:["Как только спала температура и стало легче, сразу бросить по своему суждению, ведь лекарство ценно","Даже если признаки утихли и кажется, что выздоровел, прими всё до самого конца, столько дней, сколько велено, пока микробы в теле не дойдут до нуля","Менять время приёма на разное случайное время каждый день, по прихоти","Если друг простыл, поделись с ним своим остатком лекарства"],
    answerIndex:1,
    explanation:"Когда начинаешь принимать антибиотики, сперва по порядку гибнут « слабые и многочисленные мелкие » микробы. Когда умирает примерно половина, тело чувствует себя как полностью выздоровевшее. Если тут бросить, думая « я уже здоров », те немногие « самые злобные и упрямые микробы, что вынесли удар лекарства » и ещё едва выжили, оживают и снова массово размножаются в теле. Так как эти микробы уже пережили удар и выжили, они превратились в монстров (устойчивые бактерии) с супер-сильным барьером, который лекарство уже не пробить. Тогда даже тот же препарат вовсе не действует, лечения не остаётся, и это ведёт к смерти. Принимать лекарство, не ослабляя хватки, пока не уничтожишь их полностью, — железное правило медицины, что защищает мир." },
  { id:25, topic:"Как бывает обморожение", emoji:"🥶",
    question:"Когда долго пробыл в месте крайнего холода, как заснеженная гора или лёд, почему кончики пальцев рук и ног синеют и теряют чувствительность (« обморожение »)?",
    choices:["Холодный ветер красит поверхность кожи в синий","Чтобы защитить температуру важнейших сердца и органов (центра тела), мозг сужает сосуды на кончиках пальцев и собирает кровь только в центре","В холодном месте вся кровь тела разом замерзает и перестаёт двигаться","Кончики пальцев рук и ног уснули от холода"],
    answerIndex:1,
    explanation:"Это доказательство жестокой, но высшей системы защиты ради выживания, что есть у мозга человека. Когда всё тело подвергается леденящему крайнему холоду, если бы кровь, как обычно, текла до кончиков пальцев, охлаждённая там кровь вернулась бы к сердцу, снизив температуру сердца и мозга (внутреннюю температуру) и вызвав мгновенную смерть от холода. Чтобы это предотвратить, мозг приказывает: « Пожертвуй кончиками пальцев, если надо, но никогда не дай погаснуть огню жизни центрального сердца! » Тогда сосуды рук и ног плотно смыкаются, и кровь перестаёт к ним поступать. У кончиков пальцев, не получающих крови (кислорода), клетки гибнут и синеют, а в худшем случае гниют и отпадают (обморожение). В холодных местах нужно всё время двигать руками и ногами, сразу менять мокрые перчатки и не давать мозгу отдать приказ бросить руки и ноги." },
  { id:26, topic:"Темнота и глаза", emoji:"🌙",
    question:"В миг, когда ночью входишь в тёмную комнату без электричества, ничего не видно, но если постоять неподвижно около 10 минут, очертания мебели и стен вокруг смутно проступают. Почему?",
    choices:["Из глаза человека сам собой начинает бить невидимый луч света","Чёрная дырка в центре глаза (зрачок) широко раскрывается в темноте и меняет форму, чтобы собрать как можно больше слабого света вокруг (как свет звёзд) (адаптация к темноте)","Мозг сам выдумывает тёмный пейзаж и проецирует видение","Со временем цвет ночной тьмы светлеет"],
    answerIndex:1,
    explanation:"Чёрная дырка в центре глаза человека называется « зрачок » и, как диафрагма объектива (отверстие затвора), имеет мышечную « занавеску », что сама регулирует количество входящего света. В светлом месте, как под солнцем, зрачок сжимается размером с кончик иглы, чтобы избыток света не обжёг глаз. Когда оттуда вдруг переходишь в кромешную тьму, сперва света мало и кажется совсем чёрным. Но за примерно 10 минут эта занавеска зрачка раскрывается до предела и начинает изо всех сил подбирать слабые крупинки света по углам комнаты, слишком тонкие, чтобы видеть. Эту систему называют « адаптация к темноте ». Даже в беде в темноте не паникуй: закрыв глаза и подождав неподвижно 10 минут, ты вернёшь компас своего зрения. Это мудрость человеческого тела." },
  { id:27, topic:"Наука слоёв одежды", emoji:"🧥",
    question:"Чтобы утеплиться в очень холодный сезон, почему гораздо теплее носить много тонких слоёв (слоями), чем одну толстую большую вещь?",
    choices:["Больше вещей делают одежду тяжелее, и она вытягивает тепло из земли","Между слоями образуется много слоёв неподвижного воздуха (утеплителя) — самого медленного на Земле проводника тепла, — что полностью преграждают тепло тела от ухода наружу","Когда много тонкой одежды трётся, внутри начинается пожар","От большого количества одежды ветер обходит её стороной"],
    answerIndex:1,
    explanation:"Это тоже прекрасная научная мудрость, использующая свойства вещества. Самый сильный в мире материал по тому, чтобы плохо проводить тепло (преграждать тепло), — на деле неподвижный воздух (газ). Даже если носишь одну толстую вещь, тёплое тепло тела внутри проходит по волокнам ткани и уходит наружу. Но если надеть слоями 3–4 тонкие вещи, в зазорах между одеждой образуется много « комнат воздуха, совсем запертого и неспособного двигаться ». Этот слой воздуха работает как « утеплитель », точно стенка термоса, и становится сильнейшим барьером, что не даёт уйти твоему теплу в 36 градусов и не пускает внутрь леденящий холод. Когда нет одежды, даже набить в неё сухую газету или сухие листья создаёт тот же слой воздуха и может уберечь жизнь от смерти на морозе." },
  { id:28, topic:"Бей или беги", emoji:"🏃",
    question:"Когда перед тобой вдруг появляется свирепый хищник или ты попадаешь в огромную беду, почему сердце вдруг сильно колотится и выступает холодный пот, против твоей воли?",
    choices:["Это знак, что сердце паникует от страха, ломается и вот-вот откажет","Чтобы выжить, мозг начинает готовиться « биться прямо сейчас или нестись прочь во всю мощь » и взрывообразно шлёт огромное количество кислорода (крови) к мышцам всего тела (реакция « бей или беги »)","В беде количество крови в теле удваивается","Чтобы сделать сердце громким и напугать врага напротив до обморока"],
    answerIndex:1,
    explanation:"Когда человек чувствует отчаянный страх или беду, аварийный командный центр в глубине мозга (миндалина) мгновенно чует опасность и разом выбрасывает в кровь особый гормон — адреналин. В миг, когда этот гормон доходит, насос сердца переключается на сверхбыструю работу на полной мощности, поднимает пульс с колотьём и спешно шлёт огромное количество кислорода (крови) к « мышцам ног и рук » для боя или бегства. Одновременно он сужает сосуды кожи, чтобы свести кровотечение к минимуму при ранении, поэтому лицо бледнеет и выступает холодный пот. На языке медицины это называют « реакцией бей или беги ». То, что сердце колотится, — лучший знак защиты: твоё тело, чтобы защитить тебя, высвободило всю энергию и перешло в боевой режим." },
  { id:29, topic:"Роль витаминов", emoji:"🍊",
    question:"Даже если каждый день набивать живот рисом и картошкой, почему заболеваешь (например, цингой), и кровь бьёт из сосудов по всему телу, если месяцами совсем не есть свежих овощей и фруктов?",
    choices:["Если не есть овощи, весь красный цвет крови исчезает","Трёх главных питательных веществ (как углеводы) мало; витамины, что работают как клей, крепко скрепляющий клетки, и как смазка, помогающая химическим реакциям, иссякают","У тела того, кто не ест фрукты, есть правило, что черви пожирают его изнутри","Желудок перестаёт работать, если не видит зелёный цвет овощей"],
    answerIndex:1,
    explanation:"Человек может растолстеть, питаясь рисом и хлебом (углеводами), но одним этим никак не остаться здоровым. Чтобы держать триллионы клеток и стенки сосудов тела в упругом, здоровом состоянии, непременно нужны « витамины » (особенно витамин C и другие) — микронутриенты, что тело не может создать само. Витамины — незаменимые детали для создания « коллагена (клея клеток) », что строит тело. Если их месяцами не хватает, клей клеток по всему телу рвётся в клочья, крошечные сосуды дёсен, кожи и органов повсюду рвутся, и кровь медленно сочится изнутри — страшная болезнь « цинга », и в конце ты умираешь. Не просто набивать живот, а брать малые количества витаминов и минералов — вот правда питания, что поддерживает систему жизни." },
  { id:30, topic:"Жар — это защита", emoji:"🤒",
    question:"Когда микробы простуды или инфекции входят в тело, оно дрожит и появляется высокий жар выше 38 градусов. Почему нельзя сразу силой сбивать жар лекарством — медицинская причина?",
    choices:["Если резко сбить жар, вся вода в теле превратится в кипяток","Жар — это правильная защитная реакция: мозг намеренно поднимает температуру, чтобы команда иммунитета билась лучше всего и чтобы остановить размножение микробов и вирусов, слабых перед жаром","Если сбить жар, выпадут все волосы на голове","При высоком жаре скорость бега возрастает"],
    answerIndex:1,
    explanation:"Поздравляем! На этом первые 30 вопросов « Wise World 3 » завершены. Многие ошибочно думают « жар — это плохо, надо сразу сбивать », но это большая ошибка. Многие микробы и вирусы, что вторгаются в тело, любят нормальную человеческую температуру « около 36 градусов » и размножаются там взрывообразнее всего. Но когда температура поднимается до 38–39 градусов, движение вируса парализуется, и он уже не может размножаться. Наоборот, наша команда иммунитета, как лейкоциты, при высокой температуре тела движется во много раз бодрее и быстрее. Иначе говоря, жар — это стратегия мозга намеренно поднять « температуру комнаты », чтобы взять верх в битве. Охлаждать голову, обильно пить и присматривать за жаром, которым бьётся твоё тело, не сбивая его силой, и отдыхать — вот лучшая мудрость медицины выживания, чтобы это не стало тяжёлой болезнью." },
  { id:31, topic:"Разделение труда", emoji:"🛠️",
    question:"Когда взрослые в обществе не делают все одну и ту же работу, а делятся на разные занятия - земледелец, плотник, врач (« разделение труда ») - в чём наибольшая выгода?",
    choices:["Если бы все делали одну работу, было бы трудно запоминать лица друг друга","Это снимает предел времени, когда один человек должен с нуля освоить все орудия и навыки, и когда каждый специалист сотрудничает, производительность всего общества взлетает","Заниматься разделением труда удваивает рабочие часы каждый день","Чем больше видов занятий, тем оживлённее и веселее на вид"],
    answerIndex:1,
    explanation:"Если бы не было разделения труда, тебе пришлось бы самому растить пшеницу, что ешь, самому строить дом, где живёшь, и, заболев, самому делать лекарство. Так часов в сутках никогда бы не хватило, всё выходило бы наполовину, и жить богато было бы невозможно. Человечество изобрело величайшую мудрость - « разделение труда », где каждый сосредоточен на одной работе и доводит навык до совершенства, а сделанные товары и услуги обмениваются. Это позволяет создавать во много раз более качественные результаты с меньшими усилиями и образует богатое общество, где мы поддерживаем жизнь друг друга с высшей эффективностью." },
  { id:32, topic:"Деньги - это доверие", emoji:"💵",
    question:"Бумажные купюры (валюта), что мы используем каждый день, - всего лишь клочки бумаги, так почему мы можем менять их на вкусную еду и хорошие орудия?",
    choices:["Внутри той бумаги есть волшебный ингредиент, что наполняет живот","Потому что все в обществе вкладывают в эту купюру общее « доверие »: « если я отдам эту бумагу, я всегда смогу обменять её на товар той же ценности »","Потому что закон говорит, что рисунок на купюре - самый красивый в мире","Потому что вес бумаги примерно как у куска железа"],
    answerIndex:1,
    explanation:"Истинная природа денег (валюты) - не их ценность как материала, а « система доверия » между людьми. В древности обменивали само золото и серебро, но они были тяжёлыми и неудобными в переноске, поэтому страны и общества создали общее бумажное орудие - « купюру », чьё доверие они гарантируют. Поскольку обещание и доверие в головах у всех совпадают - « даже если я приму купюру, я смогу так же воспользоваться ею в следующей лавке » - простой клочок бумаги держит мощную способность меняться на товары. В обществе, где доверие рухнуло, купюры буквально превращаются в ничего не стоящие клочки." },
  { id:33, topic:"Мера ценности", emoji:"📏",
    question:"По сравнению с жизнью обмена-бартера, какая удобная и справедливая система родилась, когда « деньги (валюту) » вставили в середину купли и продажи?",
    choices:["От использования денег вес всех товаров падает вдвое","Ценность всех товаров можно выразить общей линейкой под названием « числа », так что даже товары разных видов всегда можно справедливо сравнить по цене и обменять (мера ценности)","Использование денег значит, что торговец всегда даёт тебе подарок","Время сделки всегда становится ровно 1 секунда"],
    answerIndex:1,
    explanation:"У денег есть важная роль « меры ценности », измеряющей ценность всех товаров в числах. В мире бартера без денег тебе пришлось бы каждый раз обсуждать с другим - « во сколько рыб эта овца, во сколько мешков пшеницы, во сколько топоров? » - и расчёт превратился бы в хаос. Но как только деньги, общая линейка, появились в середине, всё можно стало сравнивать одними числами, как « овца - 10 000 монет, рыба - 500 монет ». Это позволило всем торговать справедливо и гладко, без путаницы и без убытка." },
  { id:34, topic:"Хранилище ценности", emoji:"💰",
    question:"Когда ты получаешь много еды, как рыба и овощи, почему лучше один раз превратить её в « деньги (валюту) » и сберечь, чем держать как есть?",
    choices:["Сбережение денег заставляет энергию бить из тела само собой","Еда гниёт за несколько дней, и её ценность падает до нуля, но превратив её в деньги, ты можешь « хранить плод своего труда годами, не давая ему сгнить » (хранилище ценности)","Превращение в деньги удваивает количество еды","Если положить деньги в карман, они сами сияют"],
    answerIndex:1,
    explanation:"Третья великая функция денег - « хранилище ценности ». Даже если ты усердно трудишься и собираешь огромное количество рыбы или бананов, оставив их как есть, они сгниют за несколько дней, и кристалл твоих усилий исчезнет. Так нельзя накопить богатство для будущей беды (голода или травмы). Но быстро превратив собранное в деньги, « орудие, что не гниёт », ты можешь сохранить ценность, ради которой трудился, в точности, как капсулу времени, даже на десять лет вперёд. Деньги - надёжное хранилище для защиты будущего себя." },
  { id:35, topic:"Перенос ценности", emoji:"👛",
    question:"В торговле, вместо переноски тяжёлой картошки или скота как есть, в чём чудесная выгода, с точки зрения перемещения, торговли с помощью « денег (валюты) »?",
    choices:["Держа деньги, твои ноги бегут вдвое быстрее","Ты можешь положить их в маленький кошелёк или карман и « легко перенести ценность своего имущества в любое далёкое место » (перенос ценности)","Деньги плавают на воде, поэтому можно переплыть море","Уход далеко заставляет ценность денег расти сама собой"],
    answerIndex:1,
    explanation:"У денег есть функция « переноса ценности ». Если ты хочешь пойти в дальний город и купить редкое лекарство или прочное орудие, без денег тебе пришлось бы днями тащить пешком тяжёлый урожай или быка. Риск нападения воров по дороге или гибели быка очень высок. Но если ты раз превратишь это богатство в лёгкую, маленькую форму - купюры или монеты - ты можешь спрятать её в кошелёк и в безопасности перенести огромную ценность в дальнюю землю в мгновение и торговать. Это мощная инфраструктура, чтобы экономика перешагнула границы." },
  { id:36, topic:"Договор", emoji:"📝",
    question:"Когда ты даёшь рабочее обещание кому-то или покупаешь и продаёшь товары, почему ты всегда должен оставлять письменный « договор » на бумаге, а не только устное обещание?",
    choices:["Писать много договоров тренирует мышцы руки и делает тебя сильным","Человеческая память становится смутной и меняется со временем, поэтому закрепить содержание обещания письменно предотвращает позднейшие ссоры « ты сказал, не сказал » и обман, и защищает тебя","Обещание, записанное словами, Бог автоматически исполняет волшебством","Держать бумажный документ делает тебя на вид важным"],
    answerIndex:1,
    explanation:"Один из важнейших документов для выживания в обществе - « договор ». Каким бы близким ни был друг, каким бы надёжным ни казался взрослый, ты не должен улаживать только устно обещание вроде « заплачу столько денег через несколько месяцев » или « закончу эту работу к тому времени ». Со временем непременно появится тот, кто переписывает память себе на пользу или лжёт, чтобы увильнуть. Оставив письменное доказательство с подписями и печатями обоих, даже если другой нарушит обещание, ты можешь занять силу окружающих взрослых или закона и защитить себя законно. Договор - это бронежилет для безопасной ходьбы по миру взрослых." },
  { id:37, topic:"Спрос и предложение", emoji:"⚖️",
    question:"На рынке урожай некоего боба резко упал из-за сильного дождя, и количество бобов в мире стало очень малым. Но число людей, которые их хотят, велико. В этот момент как меняется цена бобов?",
    choices:["Поскольку их мало и никто не может купить, цена становится нулём","Это становится дракой среди тех, кто их хочет, и всё больше людей готовы платить даже более высокие деньги, чтобы купить, поэтому цена бобов « резко растёт »","Что бы ни случилось, цена всех товаров всегда постоянна по всему миру","Бобы вырастают в размере, и цена немного падает"],
    answerIndex:1,
    explanation:"Это абсолютный закон, самый базовый в экономике: « спрос (желаемое количество) и предложение (продаваемое количество) ». Цена товаров решается не чьим-то капризом, а автоматически равновесием (весами) этих двух. Когда число желающих купить (спрос) становится подавляюще больше числа товаров на продажу (предложение), ценность товара (ценность редкости) взлетает. Зная эту систему, ты можешь спокойно предвидеть - « чего сейчас не хватает и что востребовано » - и составить план дела, что умно решает беды общества." },
  { id:38, topic:"Что значит прибыль", emoji:"📈",
    question:"В чём истинный, сущностный смысл в обществе получения « прибыли (заработка) » ведением дела?",
    choices:["Обманывая других, бездельничать и жить в роскоши только для себя","В результате решения того, что мучает других (неудобство или забота), своей мудростью и трудом - законно получить ценность выше затраченных издержек (закупочной цены), как « награду за твою благодарность и пользу »","Получать деньги от страны самовольно и класть в карман","Сделать имя своей лавки самым известным в мире"],
    answerIndex:1,
    explanation:"Получать прибыль в деле - вовсе не дурно и не выжимать деньги из кого-то. Прибыль считается как « (цена продажи) минус (закупочная цена или издержки создания) ». Например, для того, кто не может пойти к чистому дальнему источнику, ты несёшь ведро и черпаешь воду, и делишь за 20 монет воду, купленную за 10. Прибыль в 10 монет этой разницы - законная награда благодарности за то, что ты решил его « неудобство передвижения ». Чем больше ты решаешь чью-то боль в обществе, тем больше доверие, называемое прибылью, собирается в твоих руках." },
  { id:39, topic:"Что делает банк", emoji:"🏦",
    question:"Какова была самая основополагающая цель, ради которой место, родившееся в древности под названием « банк », ценилось людьми общества и развивалось?",
    choices:["Украшать комнату множеством красивых купюр и любоваться","Поскольку держать много денег дома рискует кражей ворами, чтобы их « надёжно хранили (вклад) » в прочном сейфе, и чтобы делать безопасные переводы (платежи) в дальние города","Внесение денег само увеличивает размер купюры","Объявить всем, у кого больше всего денег, и похвастаться"],
    answerIndex:1,
    explanation:"Первая цель, ради которой родились банки, - « нужда в надёжном хранении ». Держать золотые монеты или много купюр в своём доме несёт большой риск, что они сгорят в пожаре, или что на тебя нападут грабители и отнимут даже жизнь. Поэтому создали систему « вкладывать » деньги в место с самым прочным сейфом и охраной в обществе. Если вложить деньги в банк, они становятся записью чисел в сберкнижке, и ты можешь на 100% защитить ценное имущество от кражи. Это база мудрости, что безопасно управляет деньгами не как « физическим куском бумаги », а как « доверенными числами »." },
  { id:40, topic:"Долг и проценты", emoji:"💸",
    question:"Когда ты « берёшь деньги в долг » у другого человека или банка, какой страшный экономический механизм ты никогда не должен забывать?",
    choices:["Взятие денег в долг немного укорачивает твой рост","Мало того что ты должен вернуть взятые деньги (основу) как есть - в обмен за время, что ты их брал, ты всегда должен добавить лишние деньги сверху (проценты) и вернуть больше","Правило, что раз взяв деньги в долг, ты больше никогда не можешь делать покупки","Что взятые деньги можно держать как свои, не возвращая"],
    answerIndex:1,
    explanation:"Брать деньги в долг - это « брать вперёд » труд и свободу твоего будущего себя. Долг всегда несёт арендную плату под названием « проценты » или « ставка ». Например, если взять 10 000 монет, а правило процентов - 10%, то потом надо вернуть 11 000 монет. Если относиться к этому механизму процентов легкомысленно, сколько ни плати, расчёт процентов всё разбухает (как снежный ком), и ты кончаешь рабской жизнью, платя деньги за других всю жизнь. Если нет верного плана нарастить деньги, лёгкого долга надо абсолютно избегать." },
  { id:41, topic:"Инвестиция и трата", emoji:"🌱",
    question:"Есть два способа использовать деньги. В отличие от « траты » - купить сладости, что ешь сейчас и что сразу исчезают, - что есть конкретный пример « инвестиции », использования денег ради роста твоей будущей силы и богатства?",
    choices:["Купить много яркой одежды последней моды","Купить прочное « орудие » для начала нового своего дела, или потратить деньги на « книги (учёбу) », чтобы обрести знания","Влить все имеющиеся деньги в азартные игры в казино или в играх","Положить деньги на тарелку и просто пристально смотреть"],
    answerIndex:1,
    explanation:"Если ты только тратишь деньги (трата/мотовство), деньги просто исчезают из твоих рук, и всё. Но мудрый человек использует деньги как « семя (инвестицию) ради умножения своей будущей силы ». Например, если тот, кто строгал дерево руками, скопит деньги и купит топор хорошего качества (орудие), со следующего дня он может делать в 10 раз больше дров за то же время, и приходящие деньги резко растут. Также покупать и изучать книги по медицине или науке - сильнейшая « инвестиция в себя », превращающая собственный мозг в лучшее орудие заработка. Двигайся, рассчитывая, на что потратить деньги, чтобы будущее стало богатым." },
  { id:42, topic:"Налоги и общественные блага", emoji:"🌉",
    question:"Почему абсолютно нужна система, где все в деревне или городе понемногу вносят часть заработанных денег - « налоги » или собранные деньги (общественные средства)?",
    choices:["Чтобы использовать собранные деньги и устраивать каждый день большой праздник всем вместе","Чтобы всем вместе содержать « общий колодец, прочные дороги, большие мосты и больницы, что помогают больным (общественные блага) », что деньги одного человека никогда не создадут, и защищать общество","Чтобы собрать много денег и закопать глубоко в землю","Чтобы сделать дом некоего великого вождя роскошным, как замок"],
    answerIndex:1,
    explanation:"Если бы у общества вовсе не было налогов или денег, вносимых вместе (общественных средств), никто в одиночку не смог бы заплатить огромные деньги, чтобы возвести большой мост или замостить длинные дороги. Если дороги в руинах, никто не может передвигаться из страха травмы, и дело и жизнь полностью рушатся. Именно поэтому все понемногу вносят деньги и складывают, чтобы строить и содержать « общую инфраструктуру, что никто не сделает в одиночку (общественные блага) ». Эта система взаимной поддержки (социальная защита и общественная помощь) - сама основа благосостояния, что защищает безопасность мира." },
  { id:43, topic:"Ценность труда", emoji:"💪",
    question:"В чём сущностная, наибольшая ценность как человека от « работы (труда) » в обществе?",
    choices:["Получать приказы от кого-то и просто двигать телом, как робот","Использовать свою чудесную энергию « времени, навыка и мудрости », чтобы решить чьё-то « неудобство или беду (боль) » в обществе и сделать мир лучше, чем вчера","Работать больше часов, чем другие, ломать тело и хвастаться","Получить лицензию делать что угодно, лишь бы получать деньги"],
    answerIndex:1,
    explanation:"Истинный облик работы - не просто задача ради получения денег. Это действие создания ценности: предложить обществу своё драгоценное время жизни и навыки и превратить чьё-то « я в беде! » в « как хорошо! ». Земледелец, делая вкусную еду, стирает голод, а врач, давая лечение, стирает боль. Через работу ты нужен внутри общества и становишься важной частью головоломки, что поддерживает чью-то жизнь. Правильно знать цель работы укрепляет гордость твоей жизни и ноги твоей независимости." },
  { id:44, topic:"Опасность монополии", emoji:"👑",
    question:"Когда на рынке есть « только одна лавка », продающая некое важное лекарство (монополия), почему это очень опасно для покупателя?",
    choices:["С одной лавкой запоминать название лавки становится в тягость","Поскольку нет соперника для соревнования, даже если хозяин несправедливо вздёрнет цену до « невероятно высокой », у покупателя нет выбора, кроме как платить эти высокие деньги, чтобы жить","С одной лавкой форма лекарства сама превращается в треугольник","Опасности нет; одна лавка всегда безопаснее"],
    answerIndex:1,
    explanation:"Состояние без единого соперника на рынке называется « монополия ». Когда возникает монополия, красивые весы спроса и предложения ломаются, и продавец может свободно управлять ценой, как бог. Даже если лекарство, что должно продаваться за 10 монет, тебе объявляют « это 10 000 монет; не нравится - не покупай и болей », происходит эксплуатация, где всё твоё состояние забирают, чтобы ты жил. Именно поэтому здоровое общество защищает систему « конкуренции », где несколько лавок продают похожие товары и соперничают, и ставит барьер, чтобы цены не росли несправедливо." },
  { id:45, topic:"Слишком хорошая ловушка", emoji:"🎣",
    question:"Незнакомый взрослый сделал тебе сладкое приглашение: « Если поможешь мне с этой работой, я дам тебе в мгновение огромную сумму денег, какой ты никогда не видел ». Что надо сделать?",
    choices:["Раз это шанс получить большую сумму, помочь сразу, не думая","Категорически отказаться и уйти с места. В этом мире « работы без риска, где легко получаешь большую сумму », 100% никогда не существует; это ловушка, чтобы заставить тебя нести часть преступления и разрушить твою жизнь","Позвать много друзей и делать эту работу всем вместе","Сделать на месте бумажный договор о том, сколько получишь"],
    answerIndex:1,
    explanation:"Холодное, абсолютное правило экономики: « размер награды (полученных денег) полностью пропорционален размеру предоставленной ценности и размеру несомого риска ». За историей дать ребёнку без всякого особого навыка большую сумму в мгновение 100% спрятана зверская преступная ловушка - « перевозка наркотиков » или быть « получателем мошенничества, что обманывает людей и забирает деньги », - что одним махом приводит к аресту полицией и полностью кончает жизнь. Мудрость остерегаться оком логики тех, кто подходит со сладкими словами, и наотрез отказывать защищает твою свободу на всю жизнь." },
  { id:46, topic:"Инфляция", emoji:"🎈",
    question:"Когда « общее количество денег », что циркулирует в мире, печатается между странами и банками в чрезмерных количествах и растёт слишком сильно, что происходит с ценами всего общества (ценами вещей)?",
    choices:["Поскольку денег стало много, цена всех вещей падает до 1 монеты","Поскольку ценность редкости денег (их редкость) падает и приближается к клочку бумаги, относительно « цена всех вещей резко растёт (инфляция) »","Даже если количество денег меняется, цена вещей на Земле никогда не меняется","Вещи начинают превращаться в форму купюр"],
    answerIndex:1,
    explanation:"Это механизм « инфляции », динамичной болезни экономики. Что было бы, если бы страна печатала купюры бесконечно и раздавала всем? Поскольку у всех много денег, теперь возникает драка за « вещи ». Тогда происходит страшное явление, где хлеб, что вчера можно было купить за 100 монет, на следующий день нельзя купить без 10 000 монет, а через день - без 1 000 000 монет. Ценность денег рушится, и сила денег, что ты бережно копил, в мгновение становится мусором. Знать равновесие « количества » денег и « числа » вещей даёт тебе широкий взгляд на мир." },
  { id:47, topic:"Ловушка отложенной оплаты", emoji:"💳",
    question:"В чём скрытая величайшая ловушка системы (кредита), где « у меня нет денег сейчас, но если я покажу эту карту (или дам обещание), я могу купить прямо сейчас и заплатить в следующем месяце »?",
    choices:["В следующем месяце купленное орудие исчезает само","Поскольку деньги не убывают из твоего кошелька прямо сейчас, твоё чувство, насколько ты беднеешь сейчас, немеет, и ты кончаешь тем, что несёшь долг, что твой будущий ты абсолютно никогда не сможет оплатить","Если потеряешь карту, твоё имя полностью меняется","В момент покупки вес всего твоего тела удваивается"],
    answerIndex:1,
    explanation:"Кредитные карты и « в долг » (кредит) - очень удобные орудия, но и опасная ловушка, бьющая по слабому месту человеческого мозга. Когда « купюры » физически убывают из кошелька, человек чувствует сильную боль (страх потери) и может затормозить, но при обещании чисел (плати позже) мозг вовсе не чувствует боли. Поэтому ты беззаботно тратишь « деньги, что твой будущий ты должен заработать тяжёлым трудом ». В следующем месяце, когда не можешь заплатить, добавляются проценты, и ты банкротишься в мгновение. Жить в пределах наличных в руках - основа экономической независимости." },
  { id:48, topic:"Издержки упущенной выгоды", emoji:"⏳",
    question:"У тебя есть « 1 час » времени или « 1 000 монет » денег. Когда ты выбираешь, что с этим делать, что значит экономическое понятие, что ты никогда не должен забывать, « издержки упущенной выгоды »?",
    choices:["Особый сбор, что ты должен платить стране каждый раз при покупке","Выбрать один вариант значит одновременно, что « ты отказываешься и выбрасываешь другую чудесную возможность или ценность, что мог бы получить, если бы не выбрал его » (компромисс)","Система, где долгое использование орудия само повышает его ценность","Это значит, что время, что ты проводишь, спя дома без дела, не стоит ни одной монеты"],
    answerIndex:1,
    explanation:"Наши ресурсы, как время и деньги, « полностью конечны (имеют предел) » для всех в мире. Если ты купишь игру за 1 000 монет, возможность купить учебную книгу за эти 1 000 монет исчезает навсегда. Если потратишь 1 час на игру, возможность использовать этот час на работу или учёбу исчезает. Эту « другую наибольшую ценность, что ты тайно жертвуешь за кулисами, выбирая что-то », называют « издержками упущенной выгоды ». Мудрый человек, что это знает, решая что-то, взвешивает « делая это, что я теряю взамен? » и может сделать наименее плохой выбор." },
  { id:49, topic:"Складываться вместе", emoji:"🤝",
    question:"Когда земледельцы деревни очень хотят использовать « огромную сельхозмашину (трактор) », слишком дорогую, чтобы один человек её купил, какова мудрейшая экономическая мудрость, чтобы получить её, объединив силы?",
    choices:["Молиться каждый день и ждать, пока кто-то разбогатеет и купит её тебе в подарок","Все понемногу вносят деньги и складывают (кооператив), покупают одну машину как общее орудие всех и используют по очереди по справедливому графику","Прокрасться ночью в поле другого города и тихо украсть машину","Отказаться от покупки машины и всем делать руками всю жизнь"],
    answerIndex:1,
    explanation:"Даже если капитал одного человека (деньги, что у него есть) мал, когда много людей собираются с одной целью и вносят деньги, чтобы сделать один мощный ком, эту экономическую систему, что решает огромную задачу, называют мудростью « кооперации » или « микрофинансов ». Если использовать машину, купленную на сложенные деньги, урожай поля у всех растёт во много раз, и к всем возвращается больше денег, чем внесли. Вместо зависимости от сильного богача слабые на равных решают правила, вместе вносят средства и самостоятельно, самодостаточно создают богатство - прекраснейшая система экономической сферы." },
  { id:50, topic:"Равная сделка", emoji:"🛒",
    question:"Когда ты делаешь покупку и платишь деньги, каково правильное отношение как людей между « стороной, что платит (покупателем) » и « стороной, что продаёт (продавцом) », что принимает купюру и отдаёт товар?",
    choices:["Платящий покупатель велик, как бог, поэтому можно издеваться над продавцом","Продавец предлагает « товар чудесной ценности », а покупатель предлагает « доверенные деньги той же ценности » - они « полностью равные партнёры наравне », основанные на взаимном согласии","Лавка, что продаёт товар, более велика, поэтому покупатель всегда должен лебезить и подчиняться","Кто более велик, решается погодой того дня"],
    answerIndex:1,
    explanation:"Очень частая, уродливая ошибка в обществе - заблуждение, что « платящая сторона может задирать нос ». Дело - не верх-низ силы, а « равный, равноценный обмен » ценности друг друга. Без удобного орудия, что продавец сделал тяжёлым трудом, твоя монета в 100 остаётся простым куском металла. Наоборот, без твоих денег продавец не может купить другие вещи. Каждый оказывает другому уважение - « спасибо, что продал », « спасибо, что купил » - это смазка общества и лучшая основа, чтобы держать вращающейся добрую экономическую сферу." },
  { id:51, topic:"Видеть сквозь рекламу", emoji:"📺",
    question:"Ты увидел « рекламу (ролик) » по ТВ, в интернете, на щитах и т.п., подающую товар как невероятно привлекательный. Чего надо остерегаться, видя это?",
    choices:["То, что говорит реклама, - 100% абсолютная правда, поэтому надо всему поверить и сразу купить","Поскольку цель рекламы - « заставить тебя тратить деньги, чтобы они получили прибыль », усомнись раз в красиво украшенном виде и словах, и спокойно рассчитай, есть ли в нём сущностная ценность, что тебе по-настоящему нужна","Увидев рекламу, скажи всем друзьям « если не купишь это, заболеешь »","Все, кто появляется в рекламе, - плохие люди, поэтому надо всегда злиться"],
    answerIndex:1,
    explanation:"Техники рекламы и маркетинга сделаны, чтобы досконально исследовать человеческие чувства « хочу! » и « у всех есть, я тоже хочу похвастаться! » (слабое место психологии), чтобы заставить тебя открыть кошелёк. Даже если милый персонаж или знаменитость говорит « это лучшее », это лишь реплика, что они говорят, получив рекламные деньги. Человек, что глотает информацию СМИ как есть (без медиаграмотности), всю жизнь танцует ради чужой прибыли, и его кошелёк опустошают. Имей сообразительность видеть сквозь « цель, что за » информацией." },
  { id:52, topic:"Как работает страховка", emoji:"🛡️",
    question:"Как называют общую миру систему взаимопомощи, где против огромного несчастья-кризиса, как « тяжёлая травма, тяжёлая болезнь или большой пожар дома », о котором никто не знает, когда и с кем случится, все понемногу вносят деньги, чтобы подготовиться?",
    choices:["Покупки","Страховка (взаимопомощь)","Монополия","Сбережения"],
    answerIndex:1,
    explanation:"Если ты живёшь совсем один и вдруг получаешь тяжёлую болезнь, нуждающуюся в миллионах монет медицинских расходов, ты не можешь заплатить и теряешь жизнь вот так. Поэтому человечество изобрело « страховку », экономический щит, что мягко спасает друг друга. С пока здоровы, много людей вносят малые деньги - как 100 монет каждый месяц - в один большой сейф и копят. И когда один из членов по несчастью получает тяжёлую травму, из этого сейфа выдают большую сумму, чтобы покрыть стоимость лечения. Это прекраснейшая мудрость человечества рассеивать риск: « один за всех, все за одного »." },
  { id:53, topic:"Перелов и устойчивость", emoji:"🐟",
    question:"Рыбак, говоря « если поймаю много сейчас, заработаю много », каждый день разом вылавливал всю рыбу в море, не оставляя ни одной, вплоть до маленьких мальков (перелов). Почему это дело наверняка провалится через несколько лет и будет голодать?",
    choices:["Слишком много рыбы злит морского бога, и он превращает все купюры в песок","У природных ресурсов (растений и животных) есть « скорость восстановления » рождения детей и увеличения, и если её превысить и довести их до вымирания, то, что ты продашь в будущем, полностью исчезает (крах устойчивости)","Поймав слишком много рыбы, она становится такой тяжёлой, что лодка взлетает в небо","Когда число рыб падает, температура морской воды поднимается до 100 градусов и это опасно"],
    answerIndex:1,
    explanation:"Понятие, что никогда нельзя игнорировать, чтобы экономика длилась вечно, - « устойчивость ». Природные блага Земли - не бесконечно бьющий источник. Великий принцип - использовать рыбу и лесные деревья в пределах скорости, с какой они растут естественно, словно получая немного « процентов ». Глупый делец, что думает лишь о сиюминутной прибыли, своими руками разрушает природу, основу, и через несколько лет морит всех голодом и самоуничтожается. Имей широкий взгляд жить мудро, оставляя ресурсы детям будущего." },
  { id:54, topic:"Редкие навыки", emoji:"🧠",
    question:"Человек, что получает много « жалованья (вознаграждения) » за работу в обществе, - не просто крупный телом или тот, кто задирает нос, а человек с каким качеством?",
    choices:["Человек, что громче всех каждый день кричит, чтобы ему дали денег","Человек, у кого есть « особое знание, высокий навык, глубокий опыт », что никто другой не может легко повторить, и кто может решить большие беды общества (редкий талант)","Человек, что лучше всех в мире отлынивает в рабочие часы","Человек, что не выходит из дома каждый день и просто спит неподвижно"],
    answerIndex:1,
    explanation:"Правило, решающее размер жалованья, тоже на деле движется по закону « спроса и предложения ». У лёгкой работы, что любой может повторить за 1 секунду, есть десятки тысяч людей в мире, что могут сделать вместо тебя, поэтому жалованье низкое. Но человек со « специализированным знанием (навыком) », обретённым через долгие годы учёбы и усилий - как « я могу прооперировать и вылечить эту трудную болезнь » или « я могу разработать удобную систему, что никто не может сделать » - становится « редким, высокоценным талантом » без замены в мире. Если хочешь получать много денег, правильный ответ - не кричать громко, а шлифовать голову и навык и стать единственным в своём роде существом, что общество ищет." },
  { id:55, topic:"Польза конкуренции", emoji:"🏁",
    question:"На одной улице появились две лавки, продающие мясо, « Лавка A » и « Лавка B » (конкуренция). Какую чудесную пользу приносит покупателям (горожанам) соперничество этих двух лавок?",
    choices:["С двумя лавками вкус мяса сам превращается в шоколадный","Чтобы покупатель выбрал их лавку, каждая отчаянно начинает изобретать « сделаем цену дешевле » и « сделаем мясо свежее и вкуснее »","Две лавки каждый день яростно дерутся на кулаках, и можно смотреть","Покупка мяса всегда занимает вдвое больше времени"],
    answerIndex:1,
    explanation:"То, что соперники, продающие один товар на рынке, соревнуются, называется « конкуренция ». С конкуренцией хозяева не могут отлынивать. Если бы Лавка A продавала плохое мясо дорого, все покупатели ушли бы в Лавку B, и Лавка A обанкротилась бы. Именно поэтому каждая отчаянно работает головой и повторяет изобретение « как доставить всем дешевле и лучше ». Эта энергия конкуренции - двигатель, что заставляет технику, медицину и качество услуг всего общества развиваться всё больше каждый день." },
  { id:56, topic:"Рост производительности", emoji:"🚜",
    question:"Как называют, в экономических терминах, величайший прогресс - введение « железных орудий и тракторов (машин) », сделанных с помощью мудрости, от жизни вспашки полей руками?",
    choices:["Расширение траты","Рост производительности","Возрождение бартера","Завершение монополии"],
    answerIndex:1,
    explanation:"Даже при том же времени и той же человеческой рабочей силе увеличить количество результатов, что можно произвести, во много или в десятки раз, используя превосходные орудия, машины и системы, называется « ростом производительности ». Человек, что брал целый день руками, чтобы выкопать одну картофелину, может, используя трактор, собрать 100 картофелин за один час. Когда производительность растёт, еда и богатство переполняют общество в больших количествах, и даже без того, чтобы все работали долгие часы, потея как рабы, можно создать свободное время (досуг), где все могут жить безопасно, не спеша и богато. Мудрость облегчает труд." },
  { id:57, topic:"Торговля и распределение", emoji:"🚢",
    question:"В чём чудесный смысл системы « торговли » или распределения, где ты обмениваешь редкую соль или лекарство, что никогда не добыть в своём регионе, на одежду, что есть у людей в дальнем, ином регионе?",
    choices:["Уход далеко смешивает названия стран друг с другом и заставляет их исчезнуть","Обменивая сделанное с использованием « сильных сторон ресурсов и климата, в которых хороша каждая земля Земли », все могут поровну наслаждаться богатством, что один регион никогда бы не добыл","Заниматься торговлей сжимает размер Земли вдвое","Правило, что покупка дальних товаров всегда выращивает плесень на купюрах"],
    answerIndex:1,
    explanation:"На Земле всегда есть неравенство ресурсов по регионам: холодные места, тёплые места, места с многими горами, места у моря. Если запереться в одной деревне, живя самодостаточно, люди в регионах, где не добыть соль, заболевают и умирают. Человечество развило мудрость « распределения и торговли », связывая и обменивая с дальними регионами фирменные продукты, сделанные с использованием силы каждой земли. Это создало глобальную сеть взаимопомощи, где все люди мира делятся друг с другом благами всей Земли и могут безопасно черпать богатство, где бы они ни были." },
  { id:58, topic:"Асимметрия информации", emoji:"🔍",
    question:"Когда ты идёшь купить орудие, почему ты не должен покупать сразу только по цене, увиденной в первой лавке, а обойти несколько других лавок и рынок, чтобы посмотреть их цены (собрать информацию)?",
    choices:["Много ходить усиливает трение подошв твоей обуви и заставляет бегать быстрее","Если между продавцом и покупателем есть « разрыв информации (состояние, где только одна сторона знает правду) », есть опасность, что тебя заставят купить по несправедливо высокой цене (надувательство) выше рыночной и ты сильно потеряешь","Обход многих лавок превращает цвет купюр в красивое золото","Закон, что покупка в одной лавке огорчает человека лавки"],
    answerIndex:1,
    explanation:"В деле непременно есть плохие люди, что, пользуясь тем, что покупатель не знает истинной ценности или рыночной цены (средней цены) товара, вздувают цену в 10 раз против обычной и пытаются обмануть. В экономических терминах это называется « асимметрия информации ». Чтобы не попасть в эту ловушку, перед тем как открыть кошелёк, собрать самому « данные информации », открыв книги или обойдя несколько лавок, - сильнейший барьер. У того, у кого нет знаний, забирают деньги, а тот, у кого есть верная информация, может защитить себя - такова суровая реальность общества." },
  { id:59, topic:"Пожертвование и дарение", emoji:"🎁",
    question:"Не прося никакой отдачи, действие поделиться своими деньгами или едой с человеком, по-настоящему без денег в беде, или с человеком, что ранен и не может работать (пожертвование или дарение) - в чём его истинная мудрость в обществе?",
    choices:["Просто бросить деньги в канаву и нарочно сделать себя бедным ради забавы","Убирая из общества « людей, что в отчаянии могут лишь свернуть к преступлению » или « людей, что умирают от голода », и поднимая безопасность (порядок) и доброту всего города, ты можешь, в свою очередь, надёжнее всего защитить свою собственную жизнь и будущую безопасность","Дать деньги другим заставляет новые деньги падать с неба на следующий день","Задирать нос перед человеком в беде и чувствовать себя ставшим великим богом"],
    answerIndex:1,
    explanation:"Истинная природа « пожертвования или дарения » без отдачи - не просто самопожертвенное волонтёрство. Это инвестиция в мудрейшую « социальную сеть безопасности (линию обороны) », чтобы предотвратить страшный крах порядка, где у общества выпадает дно и люди в бедности не могут жить без совершения преступления. Добрые деньги, что ты сегодня использовал, чтобы спасти чужую боль, возвращаются к тебе, в свою очередь, как наибольшая ценность безопасного города, где завтра ты сам не подвергаешься нападению воров. Пускать доброту по кругу - величайшая социальная мудрость человечества, чтобы выжить, не самоуничтожаясь." },
  { id:60, topic:"Стать хозяином денег", emoji:"🧭",
    question:"Узнав в Пакете 2 этого приложения « Wise World 3 » о системе доверия за многой экономикой и купюрами, какова истинная конечная цель в твоей собственной жизни?",
    choices:["Накопить больше всех денег в мире и стать королём, что командует другими и правит ими деньгами","Не стать рабом денег, орудия чисел, а верно видеть сквозь « систему доверия и благодарности » за купюрами, использовать свою мудрость, чтобы мягко править деньгами, и владеть ими, чтобы защищать права человека и счастье себя и окружающих","Делать покупки до предела каждый день и наполнить дом мусором, конец","Получить трофей за все верные ответы и совсем бросить учиться"],
    answerIndex:1,
    explanation:"Поздравляем! На этом все 30 вопросов Пакета 2 завершены. Деньги, если использовать их на шаг неверно, превращаются в страшную дьявольскую цепь, что заставляет людей сомневаться, заставляет предавать и крадёт свободу людей на всю жизнь. Но если ты держишь « компас экономической мудрости », что узнал в этой викторине, тебя уже не обманут числа на купюрах. Деньги - лишь удобное орудие, что делает « энергию доверия », рождённую, когда ты решаешь чью-то беду, легко переносимой. Вместо того чтобы быть управляемым деньгами, используй свою мудрость, чтобы стать « хозяином, что мягко их контролирует ». И, на равных и справедливо с друзьями по всему миру, сотрудничай, чтобы построить своими руками добрый мир, где никто не голодает. Весь мир болеет за твою мудрую независимость!" },
  { id:61, topic:"Скорость и безопасность", emoji:"🛣️",
    question:"Ты идёшь домой, пока не стемнело. Есть «безопасный широкий обход», который занимает 1 час пешком, и «опасный короткий путь», по которому ты дома за 10 минут, но почва там осыпается и есть риск сорваться с обрыва. Что выбрать?",
    choices:["Хочу поскорее домой и играть, поэтому бегу по опасному короткому пути","Пусть дольше и я устану, но надёжно иду домой по «безопасному широкому обходу», где риск погибнуть наименьший","Закрыв глаза, решаю на бегу, какой путь лучше","Сажусь на коротком пути и отдыхаю, пока не стемнеет"],
    answerIndex:1,
    explanation:"Это базовая задача о «компромиссе» между временем (скоростью) и безопасностью, где выигрыш в одном означает потерю в другом. Короткий путь за 10 минут заманчив, но если почва осыплется и ты сорвёшься с обрыва, можно тяжело покалечиться или погибнуть и уже никогда не вернуться домой. Действие с риском, что «99 раз всё хорошо, но одна неудача обрывает жизнь», — наихудший выбор и с точки зрения экономики, и с точки зрения шансов выжить, и его нельзя выбирать никогда. Пусть ценой лишнего времени и усталых ног, выбрать безопасную дорогу, где шанс выжить близок к 100%, — вот истинная мудрость управления риском." },
  { id:62, topic:"Сохранение еды", emoji:"🧂",
    question:"После огромного урожая у тебя больше свежего мяса и рыбы, чем один человек сможет съесть. Но через несколько дней всё протухнет. Какое разумное действие с наименьшим риском здесь?",
    choices:["Жалко, если протухнет, поэтому прямо сейчас в одиночку съедаю всё, пока живот чуть не лопнет","Делюсь с товарищами и семьёй, чтобы поесть вместе, или беру на себя труд приготовить и превратить в «припас», засолив или высушив","Оставляю в комнате, пока не протухнет, и ем, когда начнёт пахнуть","Так и закапываю в землю и прячу"],
    answerIndex:1,
    explanation:"Это компромисс между «сиюминутной сытостью прямо перед тобой (потребление)» и трудом по переработке ради будущего — «будущей безопасностью (вложение)». Если через силу съесть всё в одиночку, есть риск тяжёлого отравления, которое испортит живот и может стоить жизни. Взяв на себя труд засолить и высушить (сделать сушёную еду), ты отнимаешь воду, нужную микробам, вызывающим гниение, и превращаешь еду в щит, который можно есть месяцами. А поделившись с товарищами и заслужив их благодарность (доверие), ты строишь лучшую страховочную сеть: они помогут тебе, когда ты будешь голодать в будущем." },
  { id:63, topic:"Групповое давление", emoji:"🗳️",
    question:"Пятеро товарищей делают работу вместе. Обсуждая, как двигаться дальше, четверо говорят: «Так проще, давай нарушим правила и продолжим». Но, по-твоему, у этого способа большая опасность (ошибка, риск аварии). Как поступить?",
    choices:["Мнение большинства из 4 человек (толпы) всегда должно быть верным, поэтому молча подчиняюсь","Боюсь, что друзья меня невзлюбят, поэтому, хоть и знаю, что опасно, ничего не говорю и иду со всеми","Независимо от числа людей, спокойно объясняю научное и логическое «доказательство опасности» и убеждаю всех перейти к безопасному способу, соблюдающему правила","Злюсь и убегаю куда-то один"],
    answerIndex:2,
    explanation:"Склонность человека поддаться мнению толпы и принять ошибочное решение называется «групповым давлением (давлением конформизма)» или «ловушкой группового мышления». Голосование большинством — удобный механизм, но в мире науки и безопасности «сколько людей согласны» ни на миллиметр не доказывает правоту. Даже если 4 человека скажут «всё в порядке», игнорирование законов физики или правил безопасности означает, что авария случится со стопроцентной вероятностью и захватит всех. Если ты по-настоящему ценишь жизни товарищей, признак мудрого лидера — мужество преодолеть страх быть нелюбимым (цену) и на основе твёрдых доказательств поднять голос: «здесь опасно»." },
  { id:64, topic:"Решение в темноте", emoji:"🌑",
    question:"В пути через глухой лес или незнакомый край солнце полностью заходит, и наступает кромешная тьма (совсем нет света). Слышен и вой диких зверей. Как поступить наименее плохо?",
    choices:["Доверяя чутью, в спешке иду в темноте, ища выход","Идти напролом крайне рискованно — можно сорваться с обрыва или заблудиться, поэтому укрываюсь за крепким камнем или на дереве, насторожённо слежу за округой и «тихо жду наступления утра»","Бегу в темноте со всех ног, громко крича","Ложусь на землю, раскинувшись, полностью теряю бдительность и крепко сплю"],
    answerIndex:1,
    explanation:"Это задача управления риском, где взвешивают «риск двигаться» против «риска оставаться на месте». Передвигаться в кромешной тьме — всё равно что идти через минное поле с закрытыми глазами: шансы заблудиться или упасть взлетают. Оставаться на месте несёт риск встречи с дикими зверями или холода, но если спрятаться за камнем, скрыть своё присутствие и быть начеку, сжимая ветку как оружие, можно держать шансы выжить высокими. В ситуации плохой видимости, когда нельзя рассчитать риск на шаг вперёд, мировое железное правило — «не двигаться, терпеть и ждать информации (дневного света)»." },
  { id:65, topic:"Предсказание паводка", emoji:"🌊",
    question:"Яростный ливень наконец резко прекращается, и выходит солнце. Река перед тобой на вид всё ещё как обычно, но ты во что бы то ни стало хочешь сейчас же перейти эту реку на другой берег. Как рассудить?",
    choices:["Дождь прекратился, погода ясная, поэтому решаю, что можно безопасно перейти прямо сейчас, и прыгаю","Сразу после того как дождь прекратился, огромная масса воды, выпавшей на вершинах гор, с большой вероятностью с запозданием хлынет к тебе (паводок), поэтому несколько часов не подхожу к реке и наблюдаю","Иду на середину реки и останавливаюсь проверить, поднимается ли вода","Думаю, что всё будет хорошо, если перебежать в один миг"],
    answerIndex:1,
    explanation:"У человеческого мозга есть опасная ошибка мышления, называемая «искажением нормальности», когда он удобно успокаивается, опираясь лишь на ситуацию перед глазами, думая «дождь прекратился, значит, теперь безопасно». Но если взглянуть на научную причинно-следственную связь, вода сильного дождя впитывается в землю, превращается в яростный поток реки, и до того как она достигнет тебя ниже по течению, всегда возникает «задержка в несколько часов». Даже при ясном небе ужас реки только начинается. Научись воспринимать устройство природы как данные на временной шкале и тормозить домыслы своего мозга." },
  { id:66, topic:"Ловушка лёгких денег", emoji:"📦",
    question:"Незнакомый взрослый говорит: «Если донесёшь этот свёрток до того города, я прямо сейчас дам тебе денег, чтобы ты целый год жил и играл». Посмотреть, что внутри, тебе не дают. Как решить?",
    choices:["Это огромный шанс разбогатеть, поэтому с радостью беру свёрток и несу","Скрывать содержимое и предлагать неестественно большую сумму за труд ребёнка — я логически вижу, что «за этой ловушкой на 100% стоит преступление», поэтому наотрез отказываюсь и тут же убегаю","Ещё раз торгуюсь, сколько мне заплатят","Беру только половину свёртка и пробую нести"],
    answerIndex:1,
    explanation:"Как ты узнал в экономике Пакета 2, размер вознаграждения и размер риска строго пропорциональны. Когда тебе предлагают неестественно большую сумму за перенос свёртка со скрытым содержимым, внутри с высокой вероятностью «незаконные наркотики» или «краденое имущество». Если понесёшь, не зная, и попадёшься, заплатишь сокрушительную цену: тебя на годы запрут как преступника в тёмной тюрьме, и ты потеряешь всю свободу своей жизни. Когда совпадают два сигнала — «не знаю, что внутри» и «деньги без причины», — это стопроцентная тревога опасной ловушки. Используй глаза мудрости и защити собственную жизнь." },
  { id:67, topic:"Приоритеты при эвакуации", emoji:"🎒",
    question:"Случилось крупное землетрясение или наводнение, и ты должен сейчас же эвакуироваться из дома. Дома — любимая игрушка, тяжёлый ящик с деньгами и множество дорогих сердцу вещиц. Какое суждение о том, что брать при эвакуации, верное?",
    choices:["Не хочу терять сокровища, поэтому набиваю сумку доверху тяжёлыми вещами, взваливаю на спину и бегу","Тяжёлый груз мешает бежать и может стоить жизни, поэтому беру только «самые лёгкие, минимально необходимые для жизни вещи» — воду, немного еды, медицинские средства — и бегу, освободив обе руки","Целый час спокойно собираю вещи, прежде чем тронуться","Не беру ничего, кроме одной самой любимой игрушки, и бегу"],
    answerIndex:1,
    explanation:"Это компромисс в чрезвычайной ситуации между «материальным имуществом» и «собственной жизнью (временем и скоростью передвижения)». Если бежать с тяжёлой сумкой на спине, скорость ходьбы резко падает, и ты не сможешь спастись из рушащегося здания или убежать от надвигающейся воды. К тому же, если при падении обе руки заняты, можно сильно удариться головой и больше не суметь двигаться. Какой бы дорогой ни была вещь или ценной памятная вещица, если ты не выживешь, вся их ценность становится нулём. В чрезвычайный момент за одну секунду прими холодное и верное решение: «выбросить всё, кроме жизни»." },
  { id:68, topic:"Не распространять заражение", emoji:"🤧",
    question:"Проснувшись утром, ты чувствуешь себя немного плохо, кашляешь. Сегодня день важной работы (или школьного экзамена), когда ты собираешься со всеми дорогими товарищами, чтобы строить большое сооружение. Как поступить?",
    choices:["Не хочу быть обузой для всех, поэтому скрываю недомогание, иду на работу как обычно и через силу держусь до вечера","Думаю о «риске заразить товарищей своей болезнью и погубить всю команду», честно говорю домашним или руководителю и тихо отдыхаю дома, чтобы выздороветь","Всё время задерживаю дыхание, чтобы не кашлять, и продолжаю работать","На середине работы молча ухожу домой, никому не сказав"],
    answerIndex:1,
    explanation:"Это сложная задача управления риском, где взвешивают собственное «чувство ответственности (ощущение, что надо идти)» против «риска распространения заражения» для всей команды. Идти на работу через силу на первый взгляд достойно, но с медицинской точки зрения выдыхаемый тобой вирус может заражать коллег одного за другим, и через несколько дней вся команда сляжет, а проект полностью встанет — наихудшая вторичная катастрофа. Когда ты плохо себя чувствуешь, «отдых — самое ответственное действие перед обществом»." },
  { id:69, topic:"Остановить слухи", emoji:"📢",
    question:"В деревне ты слышишь слух: «Из соседнего города прямо сейчас сюда бежит страшное чудовище с дурной болезнью!» Все в панике поднимают переполох. Какое действие тебе следует предпринять первым?",
    choices:["Это серьёзное событие, поэтому спешу сказать всем друзьям и семье: «Чудовище идёт, бегите!»","Даже услышав пугающий слух, сначала успокаиваю сердце, хладнокровно проверяю, есть ли «источник (кто сказал первым)» или «твёрдые научные доказательства», и слежу, чтобы меня не увлёк ложный слух","Верю слуху и в ярости крушу всю мебель в доме","Чтобы одолеть чудовище, в одиночку хватаю оружие и выбегаю из города"],
    answerIndex:1,
    explanation:"Явление, когда во время бедствия или ЧП беспочвенная ложь или ошибочный страх взрывообразно расходятся от человека к человеку, называется «слухами (дезинформацией)» или «массовой паникой». Человек, чьим мозгом завладела эмоция страха, становится «курьером слуха», разнося его другим без проверки. Когда это происходит, по-настоящему нужные пути эвакуации забиваются, вспыхивают ссоры, и общество губит само себя. Услышав слух, сначала пусть эстафета информации «резко остановится» на тебе. А затем проверь надёжные книги или данные взрослых и подними щит подтверждения фактов." },
  { id:70, topic:"Риск одалживания", emoji:"🪓",
    question:"Друг просит на несколько дней одолжить очень острый «топор (инструмент)», которым он дорожит. Но этот друг всегда грубо обращается с инструментами и в прошлом не раз ломал вещи. Что ты ответишь?",
    choices:["Отказ испортит отношения с другом, поэтому всё равно с улыбкой одалживаю, смирившись, что его сломают","Если инструмент сломается, я не смогу работать и моя жизнь под угрозой, поэтому на основе прошлых данных мягко объясняю причины и либо ставлю безопасное условие вроде «можешь пользоваться только при мне», либо предлагаю способ, который его не повредит","Гоню его прочь, крича во всё горло: «Ты вечно всё ломаешь, поэтому нет!»","Делаю вид, что одалживаю, но вручаю сломанный топор, который совсем не режет"],
    answerIndex:1,
    explanation:"Это дилемма между «отношениями с другом (желанием одолжить)» и «защитой собственного ценного имущества (риском, что его сломают)». Всё равно одалживать, игнорируя данные о риске, лишь потому что не хочешь обидеть другого, — это просто отказ думать. Когда инструмент и вправду сломается, другу станет неловко, твой инструмент будет потерян, и ты придёшь к наихудшему исходу. Управление риском — это не просто отказать другому, а напрячь голову и придумать «запасной план (другой подход)», который снижает твой риск и при этом удовлетворяет нужды другого, и вести переговоры на равных." },
  { id:71, topic:"Кипячение воды", emoji:"🚰",
    question:"У тебя есть вода, набранная из ближнего колодца. На вид совершенно прозрачная и сверкающе чистая. Но эта вода — после вчерашнего сильного дождя. Как поступить, когда пьёшь воду?",
    choices:["На вид прозрачная, и ужасно хочется пить, поэтому залпом пью её прямо сейчас как есть","Даже ценой «времени и топлива, чтобы довести её до бурного кипения», я обязательно уничтожаю 100% невидимых микробов, прежде чем безопасно пить","Кладу в воду красивый камень, а потом пью","Молюсь воде, а потом пью"],
    answerIndex:1,
    explanation:"Это компромисс между «скоростью утолить жажду прямо сейчас» и «медицинским риском испортить живот и тяжело заболеть потом». Как ты учил снова и снова, вода после бедствия, какой бы красивой она ни выглядела, содержит примешанные вредные вещества и микробы из земли. Тот, кто экономит на изначальной цене, думая «разводить огонь — морока» или «дрова (топливо) жалко», и пьёт сырую, платит наихудшую цену в десятки тысяч раз тяжелее: умирает через несколько дней от сильнейшего поноса. Не скупись платить правильную цену ради безопасности." },
  { id:72, topic:"Соблазн опасностью", emoji:"🕳️",
    question:"Компания друзей насмехается над тобой: «Идём исследовать ту глубокую, готовую обрушиться пещеру! Кто не пойдёт — трус!» Все вот-вот войдут. Как ты поступишь?",
    choices:["Обидно слышать «трус», и раз все идут, я тоже вхожу в пещеру с ними","У оскорблений и насмешек нет ни миллиметра научной основы, поэтому я полностью их игнорирую, сам ни за что не вхожу в опасное место и изо всех сил останавливаю остальных, говоря «это правда опасно, не пойдём»","Сам не вхожу, но стою и жду у самого края входа в пещеру","Злюсь на друзей и кидаю в них камни"],
    answerIndex:1,
    explanation:"Человека, который намеренно подбивает других на опасное поведение, раздувая страх быть отвергнутым или коля гордость оскорблениями (вроде «трус»), называют «искусителем риска». Самая частая причина несчастных случаев среди детей 9–12 лет — поддаться этому групповому давлению и тяжело покалечиться, пытаясь «выглядеть круто». Мудрый человек при суждении полностью разделяет в уме словесные оскорбления (эмоцию) и физическую опасность готовой обрушиться пещеры (факт). Настоящая смелость — не броситься в безрассудный вызов, а иметь сильное, независимое сердце, способное сказать опасности «НЕТ»." },
  { id:73, topic:"Халтура и безопасность", emoji:"🏗️",
    question:"Ты собираешь крышу своего дома или деревянный мост, чтобы все переходили. Хочешь поскорее закончить и играть, так можно ли халтурить (ставить меньше гвоздей, брать тонкое дерево), чтобы ускориться?",
    choices:["Закончить прямо сейчас приятно, поэтому халтурю там, где не видно, и быстро заканчиваю","Халтура ведёт к «огромной аварии, когда всё рушится в один миг и тяжело калечит кого-то» в момент, когда позже подует сильный ветер или встанет тяжёлый человек, поэтому, пусть и дольше, строю крепко по правилам","Делаю вид, что закончено, потом бросаю работу на середине и иду играть","Только пристально слежу, не халтурят ли другие"],
    answerIndex:1,
    explanation:"Это компромисс между «собственной ленью, желающей облегчить себе жизнь сейчас» и «обрушением будущей безопасности». Структура здания и силы физики очень честны: в момент, когда сила тяжести или энергия ветра сосредотачивается на слабом месте (ошибке) халтуры, на которую человек закрыл глаза, разрушение бьёт разом, с треском. Тот, кто пострадает тогда, может быть ты сам или твоя дорогая семья. В работе мудрость мастера — «честно и крепко строить невидимую основу, даже когда никто не смотрит» — надолго хранит доверие общества и жизни всех." },
  { id:74, topic:"Траты и вложения", emoji:"🧰",
    question:"Ты усердно работал и накопил карманные деньги (бюджет), которые можешь тратить свободно. В лавке есть «броская игрушка», которой можно похвастаться перед друзьями прямо сейчас, и «крепкий рабочий инструмент», который сделает твою будущую скорость работы в 3 раза быстрее. Что умно купить?",
    choices:["Хочу, чтобы друзья назвали меня крутым прямо сейчас, поэтому покупаю броскую игрушку","Вместо того чтобы хвастаться сейчас, покупаю «крепкий рабочий инструмент (вложение)», который повышает мою будущую производительность и безопасно приносит ещё больше денег","Совсем не трачу деньги; глубоко закапываю их в землю и забываю","Не покупаю ни то ни другое и вместо этого скупаю сладости до предела и съедаю всё за один день"],
    answerIndex:1,
    explanation:"Это сложный выбор между «потреблением» и «вложением», уже появлявшийся в экономике Пакета 2. Покупка игрушки приносит удовольствие того мгновения (потребление), но карманные деньги исчезают, а твои способности ничуть не меняются. Покупка же рабочего инструмента становится семенем (вложением), которое многократно поднимает твою будущую «производительность (объём богатства, который ты можешь создать за час)». Мудрый человек не просто тратит деньги в руках, а использует их, чтобы улучшать собственные навыки и инструменты, всё крепче укрепляя ноги своей самостоятельности. Сделай деньги своим инструментом, чтобы повелевать ими." },
  { id:75, topic:"Предотвращение вторичной катастрофы", emoji:"🚨",
    question:"Старое здание перед тобой с грохотом рушится от землетрясения или пожара. В опасной зоне прямо рядом с этим зданием твой друг ранен, упал и плачет. Какое «решение неотложной помощи» тебе следует принять самым первым?",
    choices:["Хочу скорее спасти друга, поэтому, не глядя на обстановку, прямо рывком бросаюсь туда, где он упал","Думая об опасности, что если я брошусь, здание рухнет сверху и завалит нас обоих (вторичная катастрофа), сначала 3 секунды проверяю «безопасность округи (сверху и в глубине)», обеспечиваю безопасность или зову на помощь взрослого и только тогда приближаюсь","Испугавшись, бросаю друга и убегаю","Продолжаю кричать упавшему другу: «Скорее, беги сюда!»"],
    answerIndex:1,
    explanation:"В неотложной медицине и выживании абсолютное Правило 1, которое строжайше вбивают по всему миру, — «проверка безопасности округи». Когда кто-то упал перед тобой, хочется в панике сразу броситься к нему, но если это место «под готовой обрушиться стеной» или «в яме, где скопился ядовитый газ», то в момент твоего приближения ты тоже окажешься завален и упадёшь, спасателей станет ноль, и все погибнут. Это называется «вторичной катастрофой». Помогая человеку, сначала держи себя в абсолютной безопасности — это холодное, но верное железное правило." },
  { id:76, topic:"Опасность диких животных", emoji:"🐻",
    question:"В лесу ты находишь крошечного, очень милого «детёныша дикого медведя или другого хищника», бредущего в одиночку мелкими шажками. Медведицы-матери нигде вокруг не видно. Как ты поступишь?",
    choices:["Он милый, поэтому подхожу обнять его или даю ему еду из кармана, чтобы подружиться","Ни за что не подхожу; скрываю своё присутствие и быстро, тихо ухожу с этого места. Совсем рядом с детёнышем непременно таится в тени «страшная мать-зверь», ставшая крайне свирепой, чтобы защитить дитя","Беру детёныша домой и делаю его питомцем","Громко крича, гоняюсь за детёнышем животного"],
    answerIndex:1,
    explanation:"Это управление риском, опирающееся на знание повадок (доказательств) диких созданий. Когда детёныш хищника один, это не значит, что мать забросила его и исчезла. Она ищет пищу в тени поблизости или пристально следит за тобой. В момент, когда человек приближается к её детёнышу, дикое животное расценивает это как «нападение врага, пришедшего убить моё дитя», включает свой дикий рубильник на максимум и, рискуя собственной жизнью, бросается убить тебя. Не дай обмануть себя «милотой (эмоцией)» внешнего вида; предугадай «реальность защитного инстинкта (факт)» мира природы и держи безопасную дистанцию." },
  { id:77, topic:"Справедливое распределение ресурсов", emoji:"🤲",
    question:"Случилось большое бедствие или засуха, и в деревне драматически не хватает драгоценной «питьевой воды» и «лекарства» — далеко не на всех. В этом кризисе какое суждение наименее плохое?",
    choices:["Чтобы выжить самому, силой отнимаю у других их долю воды и лекарства","Драка приводит к раненым, и общество губит само себя, поэтому все вместе обсуждаем и решаем справедливое правило раздавать по очереди, начиная с самых слабых — «маленьких детей, беременных, больных», — и делимся","Выливаю всю воду и лекарство на землю, чтобы никто не мог ими воспользоваться","Сдаюсь, и все садятся на месте и плачут"],
    answerIndex:1,
    explanation:"Это управление риском общества в крайнем состоянии (кризисе), когда ресурсов не хватает до предела. Если здесь убрать правила и допустить мир насилия (закон джунглей), где сильный отнимает у слабого, в деревне вспыхнет война на истребление, и в итоге все погибнут от ран или болезней. У человека есть мудрость именно затем, чтобы в таком кризисе изобрести «правила (общественный договор)», максимизирующие шансы на выживание всей группы. Добрый и разумный механизм раздавать по очереди, начиная с самых слабых жизней, которых надо защищать больше всего, — это то, что позволило человечеству выжить сквозь суровую историю." },
  { id:78, topic:"Уважение к личному", emoji:"🔒",
    question:"В интернете или в разговоре кто-то ради забавы пытается без разрешения распространить «секретные данные или воспоминание о прошлой стыдной неудаче» твоего дорогого друга. Как ты поступишь?",
    choices:["Звучит весело, поэтому я тоже подключаюсь и разбалтываю этот секрет всем остальным","Распространять без разрешения чужие секреты или нежеланные сведения глубоко ранит сердце и права человека другого; это «насилие (травля)», которое полностью разрушает доверие и которое нельзя делать ни в коем случае, поэтому с гневом я заставляю их остановиться","Делаю вид, что не видел, и переписываю секрет друга в свою тетрадь","Насмехаюсь над другом: «Как нелепо, что твой секрет всплыл»"],
    answerIndex:1,
    explanation:"Это об опасности относиться к чужому «личному (секретам)» как к полушутке. Сила распространения слов и интернета особенно страшна: однажды разошедшийся стыдный слух о другом человеке уже никогда нельзя собрать обратно и стереть. Тот, с кем это случилось, может впасть в отчаяние и заболеть душевно или потерять силы жить. Стань человеком, способным вообразить чужую боль как свою и затормозить веселящуюся компанию, сказав «это неправильно, прекратите». Защита достоинства других возвращается к тебе по кругу, строя безопасный мир, где все защитят тебя, когда ты в кризисе." },
  { id:79, topic:"Правило заблудившегося", emoji:"🧍",
    question:"В незнакомом большом городе, бескрайней пустыне или лесу ты теряешься с семьёй или товарищами и оказываешься «потерявшимся». Вокруг нет никого, кто, похоже, мог бы тебе помочь. Как поступить?",
    choices:["Чтобы найти семью, с криком и плачем во что бы то ни стало продолжаю отчаянно блуждать во всех направлениях","Блуждание лишь уводит меня дальше и делает труднее найти, поэтому успокаиваю сердце, крепко ставлю ноги на «безопасное место, где я точно был с семьёй в последний раз», и жду, не двигаясь, пока меня найдут","Залезаю на высокое дерево на месте и провожу ночь в одиночку","Молча иду вплотную за незнакомым взрослым"],
    answerIndex:1,
    explanation:"Это доказательство выживания на случай, когда ты потерялся (риск двигаться против риска ждать). Потерявшись, если ребёнок в панике блуждает во всех направлениях, он расходится с маршрутом поиска семьи, всё дальше отдаляется и совершенно теряется. Семья и поисковые группы всегда ищут, сосредоточившись на «месте, где ты потерялся в последний раз». Именно поэтому, потерявшись, соблюдай мировое железное правило спасения: «не двигайся ни на шаг с места (Hug a Tree: обними дерево и жди)». Терпеливая мудрость не двигаться быстрее всего повышает шанс воссоединиться с семьёй." },
  { id:80, topic:"Гашение огня", emoji:"🧯",
    question:"После костра, которым ты пользовался для готовки или тепла, огонь полностью погас, и остались только чёрные угли и зола. Прежде чем вернуться в дом или палатку, что нужно сделать в последнюю очередь?",
    choices:["Красного пламени не видно, поэтому решаю, что полностью потушено, оставляю как есть и ухожу","Чтобы предотвратить опасность, что невидимый «жутко горячий тлеющий уголёк», спрятанный в глубине углей, позже, когда подует ветер, обернётся большим пожаром, снова и снова лью вёдра воды и убеждаюсь, что всё полностью остыло","Накладываю на угли много сухих листьев, чтобы их спрятать","Сильно раздуваю золу трубкой для огня и развеиваю её по ветру"],
    answerIndex:1,
    explanation:"Это холодное физическое доказательство обращения с огнём. После костра, когда поверхность покрыта чёрными углями и белой золой, человеческий глаз удобно успокаивается (искажение нормальности), думая «уже погасло». Но внутри углей яростный «тлеющий уголёк» в несколько сотен градусов выживает часами, копя жар, как термос, не пропуская воздух. Если уйти так, в момент, когда ночью сильный ветер подаст кислород, угли снова взрывообразно вспыхнут и вызовут большой пожар (лесной пожар), который в один миг сожжёт дотла окрестный лес и палатки. Мудрость лить воду, пока шипение полностью не стихнет, хранит природу и жизни во всём мире." },
  { id:81, topic:"Время и деньги", emoji:"⏰",
    question:"Загадка о покупках. На дальнем рынке в «1 часе ходьбы» от дома картофель продаётся по 50 монет. В лавке «прямо по соседству» с домом тот же картофель продаётся по 100 монет. Где умнее всего покупать?",
    choices:["50 — определённо меньшее число, поэтому что бы ни было, всегда надо идти 1 час до дальнего рынка","Ты взвешиваешь «2 часа туда-обратно, которые есть твоё собственное драгоценное время жизни» и «силы, которые тратишь на ходьбу», считаешь, стоит ли потратить эти 2 часа на что-то другое — учёбу или работу, — и сам выбираешь вариант получше","Идёшь в самую дорогую лавку и переплачиваешь продавцу","Не знаешь, что лучше, поэтому отказываешься покупать картофель"],
    answerIndex:1,
    explanation:"Это сложная задача о равновесии между числами денег и «твоим собственным временем (издержками упущенных возможностей)». Сэкономить 50 монет заманчиво, но ради этого ты платишь цену — жертвуешь «2 часами» туда-обратно. Если бы за эти 2 часа работы ты мог заработать 500 монет, то потратить 2 часа, чтобы выгадать 50 монет, означает, по вычитанию, что ты несёшь «большой убыток в 450 монет». И наоборот, если сегодня тебе совсем нечего делать и времени бесконечно много, то сходить далеко ради разминки и сэкономить 50 монет становится правильным ответом. Правильный ответ не один. Развей взрослый мозг, который переводит время в деньги и считает." },
  { id:82, topic:"Осторожность к неизвестному", emoji:"🍒",
    question:"В лесу ты находишь «красивый плод совершенно нового, абсолютно незнакомого вида, которого точно нет ни в одной виденной тобой книге или поучении взрослых». Ты ужасно голоден. Как поступить?",
    choices:["Выглядит вкусно и цвет красивый, поэтому, чтобы набить живот, прямо сейчас съедаю его весь","Думая о риске, что незнакомая еда может таить смертельный яд, в один миг разрушающий органы человека, я «ни за что не беру в рот» то, что не доказано научно безопасным на 100%","Даю другу съесть лишь чуть-чуть и ставлю опыт, не испортит ли он живот","Ополаскиваю плод водой один раз, а потом залпом проглатываю целиком"],
    answerIndex:1,
    explanation:"Это мудрость осторожности к «неизвестному (риску)» в выживании. Когда у растения или плода в природе красивый цвет или сладкий запах, это не для того, чтобы люди нашли их вкусными. Напротив, очень вероятно, что это «яростное ядовитое оружие защиты», эволюционировавшее само, чтобы животные его не ели. Правило мудрого выживальщика — не «есть только то, что знаешь как безопасное», а строгое вычитающее мышление: «обращайся со всем, что не доказано безопасным на 100%, как с ядом». Не поддавайся сиюминутному голоду и не ставь жизнь на кон." },
  { id:83, topic:"Тише едешь — дальше будешь", emoji:"🪵",
    question:"Есть 10 связок тяжёлых дров. Когда ты через силу нёс все 10 разом, ты шатался, много раз ронял груз, и ушло 30 минут. Когда ты разделил на 5 ходок по 2 связки, ты безопасно закончил переноску за 10 минут. Какую мудрость ты извлекаешь из этого результата?",
    choices:["Что нести много разом тренирует мышцы и выглядит круто","Тише едешь — дальше будешь (чем больше спешишь, тем больше берёшь безопасный, верный способ). Правильно рассчитать предел своего тела и разделить груз — в итоге самый быстрый и самый «производительный» путь","Что не нести груз, а оставить на месте — занимает меньше всего времени","Что со следующего раза надо заставить кого-то другого нести всё"],
    answerIndex:1,
    explanation:"Это компромисс между «спешкой, желающей закончить разом» и «ошибками (неудачами) из-за физических пределов тела». Чем больше человек спешит, тем больше он хочет переоценить свои силы и нацелиться на безрассудный единственный удар (короткий путь), но обычно теряет равновесие, тяжело проваливается, вынужден начинать сначала и теряет в разы больше времени и сил. Хладнокровно смотреть на данные собственных пределов и делить задачу на маленькие надёжные части, чтобы складывать их, — этот малорисковый способ делает общую скорость (производительность) подавляюще быстрее." },
  { id:84, topic:"Одежда как защита", emoji:"🦟",
    question:"В жаркий летний день ты идёшь работать в колючие заросли или глухой лес, где во множестве таятся страшные ядовитые насекомые (комары и клещи). Какая одежда — самый правильный выбор для управления риском?",
    choices:["Очень жарко, поэтому иду в прохладной, удобной короткой футболке, шортах и босиком","Даже ценой того, что вспотею от жары, чтобы острые колючки и жала насекомых не достали кожу напрямую, надеваю «рубашку с длинным рукавом, длинные штаны и крепкую обувь» из плотной ткани, полностью пряча кожу","Жалко пачкать одежду, поэтому иду голым, ничего не надев","Надеваю самую роскошную и красивую одежду, что есть дома"],
    answerIndex:1,
    explanation:"Это дилемма между «комфортом, желающим прохлады прямо сейчас (эмоцией)» и «защитой твоей кожи (безопасностью)». Если из-за жары оголить кожу и войти в густые заросли, не только колючки оставят кожу в крови, но комары и клещи, несущие вирусы страшных болезней (таких как малярия и лихорадка денге), искусают тебя во множестве, и через несколько дней ты сляжешь с жаром в 40 градусов, взяв на себя риск в десятки тысяч раз страшнее. Одежда — это «первый и сильнейший медицинский барьер» через физическую стену волокон ткани. Ради безопасности обладай мудростью терпеть нынешнее неудобство (жару)." },
  { id:85, topic:"Управление гневом", emoji:"😤",
    question:"На середине работы или разговора с другом собеседник говорит тебе несправедливую гадость или по неосторожности ломает твой ценный инструмент. Грудь пылает от гнева, и хочется ударить его. Как поступить?",
    choices:["Поддавшись эмоции гнева, ору во весь голос и со всей силы бью его в ответ","Если гнев захватит мой мозг, я не смогу хладнокровно рассчитывать и понесу большой убыток — устрою акт насилия и буду арестован полицией, поэтому один раз закрываю глаза, «3 раза глубоко дышу», чтобы остудить мозг, и излагаю факты словами","Мне досадно, поэтому иду домой и со всей силы бью по стене своей комнаты, ломая её","Ничего не говоря, тайком напихиваю много камней в обувь собеседника"],
    answerIndex:1,
    explanation:"Это контроль над собственной «эмоцией гнева (порывом)» и «предвидением наихудшего результата, который последует» (управление гневом). В момент, когда человек чувствует гнев, первобытная часть мозга (миндалевидное тело) выходит на полную мощность, а выключатель лобной доли, управляющей разумом, временно полностью отключается. Если в эмоции тех «нескольких секунд, когда голова поглупела» применить насилие, заплатишь наихудшую цену: тяжело покалечишь собеседника, станешь преступником или построенное доверие исчезнет в один миг. Несколько секунд терпения, чтобы глубоко вдохнуть, подать кислород в мозг и снова включить разум, спасают твою жизнь от краха." },
  { id:86, topic:"Жизнь дороже инструментов", emoji:"⛰️",
    question:"По неосторожности ты роняешь очень дорогой и ценный «железный нож (инструмент)», которым пользуешься для поделок и работы, в кусты на дне глубокого осыпающегося обрыва. Как рассудить?",
    choices:["Не хочу терять дорогой и ценный инструмент, поэтому даже без верёвки в спешке съезжаю по склону обрыва и спускаюсь поднять его","Инструмент можно когда-нибудь купить снова, если заплатить, но мою собственную жизнь уже никогда не купить заново. Если опора опасна, отказываюсь лезть за ним через силу или зову на помощь взрослого с безопасными инструментами","С вершины обрыва продолжаю кричать ножу: «Вернись»","Бросаю много тяжёлых камней туда, куда упал нож"],
    answerIndex:1,
    explanation:"Это предельный компромисс между «денежной ценностью» инструмента и собственной «физической безопасностью». Когда теряешь дорогую вещь, человеческий мозг наполняется спешкой и желанием не понести убыток (искажение неприятия потерь), и окружающая опасность становится невидимой. Но по законам физики можно на 100% рассчитать, что человек без верёвки, спускаясь по осыпающемуся обрыву, полетит вниз головой, сломает череп и потеряет жизнь. Инструмент — «заменимая деталь», которую деньги или труд всегда могут заменить, но твоя жизнь — единственный «незаменимый высший секрет», которого в мире лишь один. Никогда не путай вес вещи с весом жизни." },
  { id:87, topic:"Доказательства важнее авторитета", emoji:"📚",
    question:"О том, как лечить некую болезнь, двое взрослых в деревне дают совершенно разные советы. Человек А говорит: «Это поверье из глубокой древности, поэтому ты вылечишься, если прочтёшь это заклинание», а человек Б говорит: «В научной книге написано, что если прокипятить эту лекарственную траву и выпить, её вещество подействует». Кому ты поверишь?",
    choices:["Человек А старше и борода у него длиннее, поэтому верю тому, что говорит человек А","Не давая себя обмануть поверьям или внешности говорящего (авторитету), верю и исполняю «совет из книги человека Б», который несёт реальные данные о лечении и доказательства опытов (научные доказательства)","Смешиваю оба мнения и ем сырую траву, читая заклинание","Не могу поверить ни тому ни другому, поэтому в ярости кричу и буяню в комнате"],
    answerIndex:1,
    explanation:"Это управление риском — судить о «правильности» информации по возрасту или внешности говорящего (авторитету) или по «твёрдым данным фактов (доказательствам)». Среди древних поверий есть чудесная мудрость, но в них же примешаны ошибочные ворожбы и опасные домыслы, что наоборот ухудшают болезнь. В решении медицины или науки, где на кону человеческая жизнь, лишь те, у кого логический взгляд и кто хладнокровно докапывается, «есть ли в мире статистика или доказательства (данные), что это и вправду вылечило кого-то», — а не кто это сказал, — могут избежать ловушки и выжить." },
  { id:88, topic:"Уход за мелкими ранами", emoji:"🦶",
    question:"На середине работы на улице маленькая колючка вонзается тебе в подошву, и выступает немного крови. Но прямо сейчас ты в разгаре весёлой игры со всеми (или в разгаре спешной работы). Что ты сделаешь с этой маленькой раной?",
    choices:["Стыдно говорить всем о такой маленькой ране, поэтому держу её в секрете и продолжаю двигаться, оставляя до ночи","Думая о риске, что невидимые микробы грязи войдут через маленькую рану и потом вся стопа сгниёт так, что я не смогу ходить, один раз останавливаюсь, тут же промываю чистой водой и обрабатываю с дезинфекцией","Нарочно стираю кровь с раны, растерев грязью","Пальцем заталкиваю колючку в подошве ещё глубже"],
    answerIndex:1,
    explanation:"Это проблема оставленной ошибки, когда ты оставляешь маленький риск, думая «да ладно», и даёшь ему вырасти позже в непоправимую катастрофу. Если взглянуть на историю медицины, каким бы здоровым и сильным ни был человек, случались миллионы происшествий, когда микробы (столбняк или сепсис), вошедшие через маленькую рану, через несколько дней расходились по крови всего тела, и в среде без врача ногу ампутировали или жизнь терялась. Секрет управления риском — в ежедневной привычке прилежного самоухода: «на самой ранней стадии (прямо сейчас), когда риск наименьший и его легче всего задавить, надёжно обработать и пресечь в зародыше»." },
  { id:89, topic:"Предвестники бедствия", emoji:"🌋",
    question:"Ты живёшь у вулкана или у большой реки. Однажды раздаётся жуткий гул земли, какого ты никогда не слышал, и дикие животные вокруг разом убегают с горы. Но другие взрослые беззаботно смеются, говоря: «Это как всегда, поэтому всё в порядке». Как поступить?",
    choices:["Взрослые вокруг смеются, поэтому я тоже спокойно сплю дома как обычно","Я верю явному знаку большого бедствия (данным-предупреждению), который посылает мир природы, не даю увлечь себя беспечности окружающих и, пусть это будем только я и семья, тут же собираю вещи и заранее эвакуируюсь на безопасную возвышенность","Жду неподвижно на месте, пока взрослые не убегут","Гонюсь за животными и ухожу в глубь горы"],
    answerIndex:1,
    explanation:"Прямо перед большим бедствием многие люди убеждают себя «только со мной всё в порядке» или «другие не двигаются, значит, ещё ничего», слишком медлят с бегством и гибнут все вместе. Эту наихудшую ошибку группового мозга называют «плюралистическим неведением» или «искажением нормальности». Создания великой природы более острыми, чем у человека, чувствами улавливают опасные мельчайшие колебания земли и запах газа (данные) и за секунду переходят к защитному поведению. Не смотри на «человеческое настроение (эмоцию)» вокруг; верь только данным «физических знаков (фактов)» природы и стань мудрым выживальщиком, способным рвануть на эвакуацию первым пингвином, раньше всех." },
  { id:90, topic:"Итог управления риском", emoji:"🦉",
    question:"Вопрос тебе, прошедшему Пакет 3 этого приложения «Wise World 3». Что за сила — истинная суть «лучшего управления риском (предсказания риска)» для того, чтобы безопасно, мудро и самостоятельно прожить в мире?",
    choices:["Сила громко рыдать после того, как что-то случилось, и чтобы кто-то меня спас","Сила не дать обмануть себя эмоцией или домыслом перед глазами, использовать научные данные, чтобы в голове в нескольких вариантах прочитать наперёд будущий причинно-следственный маршрут «если я сделаю это, какой наихудший результат случится дальше», и самому решить безопасный маршрут и двинуться, прежде чем станет опасно","Сила сделать мышцы толще, чем у других, и кулаками сбить всякую опасность","Сила беззаботно продолжать верить, что со мной никогда не может случиться ничего плохого"],
    answerIndex:1,
    explanation:"Поздравляем! На этом все 30 вопросов Пакета 3 завершены. Реальный мир не такое всегда безопасное и доброе место, как сказка. Внезапные бедствия, ловушки сладких слов, групповое давление толпы — опасности, что пытаются утянуть тебя к гибели, таятся всегда. Но если у тебя есть «компас компромиссов и управления риском», который ты освоил в этом пакете, бояться больше нечего. Управление риском — не стать робким и запереться в комнате; это правильно изучить истинный облик опасности (законы физики и ошибки человеческой психологии), сохранить его как данные в голове, ловко обходить опасные места и отправиться в великое приключение по миру свободно и сильно — «величайший и сильнейший щит мудрости». Используя мудрый интеллект выживания, зажжённый в твоём мозгу, и впредь надёжно береги собственную жизнь и будущее своих дорогих товарищей. Весь мир от души болеет за успех твоего пути к самостоятельности!" },
  { id:91, topic:"Алгоритм", emoji:"📋",
    question:"Как называется «правильная упорядоченная последовательность команд», которую ты даёшь компьютеру или ИИ, чтобы он выполнил работу максимально эффективно и без багов (ошибок)?",
    choices:["Пароль","Алгоритм","Интернет","Загрузка"],
    answerIndex:1,
    explanation:"«Конкретный порядок действий или правило вычисления» для выполнения работы называется «алгоритмом». Например, кулинарный рецепт или порядок сверки с картой, чтобы не заблудиться в горах, — тоже разновидность алгоритма. Компьютеры очень быстры, но если человек не выстроит этот алгоритм правильно при команде, они работают неэффективно и зависают или выдают неверный результат (баг) и причиняют большой ущерб. Способность логически выстраивать вещи и продумывать шаги, дающие наибольший результат при наименьших времени и энергии, станет мощным оружием для выживания в грядущую эпоху." },
  { id:92, topic:"Как устроен интернет", emoji:"🌐",
    question:"Смартфоны и компьютеры всего мира соединяются как сеть и доставляют данные далеко за мгновение. В чём наибольшая сила устройства «интернета»?",
    choices:["Он соединён лишь одной большой линией, поэтому если линия где-нибудь оборвётся, всё мировое сообщение разом остановится","Он превращает данные в крошечные рассеянные «пакеты (посылки)» и отправляет каждый по отдельному маршруту среди бесчисленных путей мира, так что связь не прерывается, даже если часть дороги разрушена (распределённая сеть)","Использование интернета делает все машины вдвое легче","Чем больше ты общаешься, тем больше денег автоматически прибавляется"],
    answerIndex:1,
    explanation:"Интернет — это не одна большая базовая станция, правящая миром; это «распределённая» сеть, где бесчисленные компьютеры соединены как равные. Фото или текст, которые ты хочешь отправить, — не единый ком, а мелко разбиты на «пакеты», невидимые маленькие крупинки, и каждый путешествует к машине-получателю по отдельному свободному маршруту. В миг прибытия они воссоединяются в исходную чистую форму. Благодаря этому, даже если большое бедствие где-то перережет линию связи, пакеты автоматически находят другой маршрут и обходят его, не давая связи всего мира полностью парализоваться." },
  { id:93, topic:"Сильный пароль", emoji:"🔑",
    question:"Чтобы защитить важный онлайн-аккаунт от воров (хакеров), какой способ создать «трудновзламываемый пароль» самый безопасный?",
    choices:["Использовать свой день рождения или что-то вроде «123456» — простые, легко запоминающиеся цифры","Сделать его «длинной строкой, смешивающей английские заглавные и строчные буквы, цифры и символы», которую никто не угадает и которой нет ни в одном словаре, и не использовать тот же самый в других приложениях","Написать своё имя прямо по-английски","Написать пароль на бумаге и приклеить рядом с экраном компьютера"],
    answerIndex:1,
    explanation:"Пароль аккаунта — это «ключ», охраняющий твой цифровой дом. Плохие люди используют компьютеры, чтобы перебирать «обычные слова» и «простые сочетания цифр» миллионы раз в секунду, пытаясь открыть замок (атака грубой силой). Если ты используешь день рождения или повторно используемый простой пароль, его взломают за мгновение и украдут все твои драгоценные деньги и личные данные. Создать непредсказуемый ключ из 12 и более символов со случайно перемешанными знаками и приготовить отдельный ключ для каждого сервиса — это первая линия обороны, надёжно предотвращающая ущерб от цифровых преступлений." },
  { id:94, topic:"Фишинг", emoji:"🎭",
    question:"На твоём экране появляется уведомление: «Ваш аккаунт приостановлен. В течение 10 минут нажмите этот URL (ссылку) и введите пароль и имя для подтверждения». Как ты рассудишь?",
    choices:["Потерять аккаунт было бы ужасно, поэтому я спешу нажать ту ссылку и ввожу все свои данные","Я вижу, что это с большой вероятностью «фишинг», который обманывает поддельным экраном и крадёт деньги, поэтому я ни за что не нажимаю ссылку, один раз закрываю экран и проверяю с официального настоящего сайта","Я отправляю копию этого экрана всем друзьям, и мы пробуем войти вместе","Я громко кричу на экран"],
    answerIndex:1,
    explanation:"Это очень подлая преступная ловушка под названием «фишинг», которая ввергает в панику твои «чувства спешки и страха», заставляет потерять рассудок и ввести пароль самому на поддельном сайте. Настоящий банк или официальная компания на 100% никогда не будут угрожать тебе в письме или подозрительном уведомлении «немедленно войти и ввести личные данные». Если внимательно посмотреть на показанный URL, это поддельная строка, сделанная похожей на настоящее имя компании (отличие в одну букву, например). Увидев подгоняющие слова, сначала затормози мозг и используй «цифровую грамотность» сомнения в информации, чтобы полностью избежать ловушки." },
  { id:95, topic:"Цифровая татуировка", emoji:"👣",
    question:"Какова главная причина, по которой нельзя легкомысленно выкладывать своё настоящее имя, фото лица, местоположение дома или ежедневный маршрут в школу в соцсетях или приложениях интернета?",
    choices:["Выложишь фото в сеть — у смартфона вдруг сядет батарея","Раз данные стали публичными в сети, другие за мгновение копируют (сохраняют) их, и они расходятся по всему миру, поэтому их уже никогда нельзя полностью стереть, и их могут пожизненно использовать в преступлениях вроде преследования или похищения (цифровая татуировка)","От большого количества текста трескается стекло экрана","Есть закон, что детям нельзя писать текст в мире сети"],
    answerIndex:1,
    explanation:"Информация, написанная в интернете, остаётся в море сети, как татуировка, что никогда не сходит, поэтому её называют «цифровой татуировкой». Даже фото лица или данные о месте, которые ты выложил «с намерением показать только друзьям», могут за мгновение, одной кнопкой, быть перепосчены сотням миллионов незнакомцев по всему миру и использованы плохими людьми в жестоких преступлениях вроде похищения, где они вычисляют тебя и устраивают засаду. Твои личные данные — высший секрет для защиты собственной жизни и свободы. Впечатай в мозг холодное правило цифрового мира: раз выложил — невозможно отмотать время назад и стереть это." },
  { id:96, topic:"Проверка фактов", emoji:"🔎",
    question:"Ища в интернете, ты находишь поразительную статью: «Говорят, если есть мясо, что продаётся в том супермаркете, поумнеешь и все болезни вылечатся!» Как наименее плохо обойтись с этой информацией?",
    choices:["Это чудесное великое открытие, поэтому я сразу верю и иду покупать то мясо в большом количестве","Я проверяю с разных сторон, кто написал статью (эксперт или просто чей-то дневник) и есть ли тот же факт (доказательство) в других надёжных научных книгах или данных (проверка фактов)","Я копирую эту статью и распространяю всей группе друзей со словами «ешь скорее, а то умрёшь»","Я делаю вид, что не видел статью, и швыряю смартфон на землю"],
    answerIndex:1,
    explanation:"В море информации интернета содержится не только верное знание, подобное алмазам, но и поток небрежной лжи (дезинформации), заблуждений и мусора, сделанного, чтобы намеренно обманывать людей ради наживы. Именно потому, что любой может одной кнопкой распространять ложь, тот, кто проглатывает увиденный текст как есть, становится «виновником», распространяющим ложную информацию, или «жертвой», у которой впустую отнимают деньги. Встретив информацию, мудрость «проверки фактов» — выяснить по нескольким маршрутам «где источник?» и «есть ли твёрдые данные-доказательства?» — защищает безопасность твоего мозга." },
  { id:97, topic:"Пузырь фильтров", emoji:"💬",
    question:"ИИ интернета и соцсетей изучает твою прошлую историю поиска и автоматически собирает на экран только «мнения, которые тебе вроде нравятся» и «истории, с которыми ты захочешь согласиться». В чём наибольшая скрытая ловушка этого состояния (пузыря фильтров)?",
    choices:["Раз ты видишь только то, что нравится, все люди в мире могут стать счастливыми","Противоположные тебе мнения и верные научные данные (факты) перестают попадаться тебе на глаза, поэтому ты убеждаешь себя, что только твой взгляд на 100% верен, твоё предубеждение крепнет, и ты принимаешь неверные решения","Весь текст на экране меняется на английский","Из смартфона автоматически выскакивают сладости"],
    answerIndex:1,
    explanation:"Чтобы получать рекламную прибыль, удерживая тебя долго у экрана, ИИ сети запирает тебя внутри пузыря только из приятной информации, подобранной под твой вкус. Это называют «пузырём фильтров» или «явлением эхо-камеры». Внутри этого пузыря ты впадаешь в иллюзию, что все в мире думают так же, как ты, и твой кругозор сужается до крайности. Чтобы охватить верную целостную картину и принять наилучшее решение, нужен активный баланс мышления: намеренно своей рукой открывать комнату «мнений, отличных от твоих» и «холодных научных данных»." },
  { id:98, topic:"Шифрование данных", emoji:"🔐",
    question:"Отправляя кому-то важное сообщение, как называется технология, что превращает текст в сложный рассеянный шифр, чтобы содержимое абсолютно нельзя было раскрыть, даже если вор подсмотрит его по пути?",
    choices:["Переработка","Шифрование (шифрование данных / E2EE)","Фотосинтез","Инфляция"],
    answerIndex:1,
    explanation:"Сильнейший щит для безопасного хождения по интернету — технология «шифрования». Например, когда ты отправляешь текст «привет», данные мгновенно, прежде чем пройти по дороге интернета, превращаются в строку совершенно бессмысленных символов вроде «x9F2m7q». Даже если плохой шпион, подсматривающий связь по пути, украдёт данные, при шифровании содержимое прочесть нельзя. И лишь в миг, когда они достигают машины твоего друга-получателя, они чисто восстанавливаются в исходный «привет» «верным ключом (закрытым ключом)», который есть у друга. Благодаря этой технологии мы можем спокойно совершать покупки и общаться, защищая приватность." },
  { id:99, topic:"Резервная копия", emoji:"💾",
    question:"Чтобы подстраховаться от случайного удаления драгоценных данных или файлов викторины, сделанных с усердием, или от поломки машины, как называется действие — сохранять точную копию в другом безопасном месте (другой папке, на USB и т. п.)?",
    choices:["Обновление","Резервная копия (бэкап)","Отладка","Программирование"],
    answerIndex:1,
    explanation:"Цифровые данные очень удобны, поскольку не имеют физической формы, но одновременно несут роковой риск (уязвимость), что «из-за поломки машины или ошибки управления всё может полностью исчезнуть за мгновение». Единственная мудрость, предотвращающая великую трагедию превращения в ноль сокровища, сделанного за много дней, — это «резервная копия». Храня точный клон данных на другом жёстком диске или сервере в дальнем месте (в облаке), даже если основная машина сгорит в пожаре или сломается, ты можешь за одну секунду на 100% восстановить и оживить исходное богатое состояние. Это базовая привычка информационного общества: распределять риск, готовясь к непредвиденному." },
  { id:100, topic:"Анонимность в сети", emoji:"🕵️",
    question:"Ты написал оскорбления или ложные слухи о ком-то на интернет-форуме или в соцсети. Правда ли, что никто никогда не узнает, кто написал, пока ты используешь «анонимное имя (псевдоним)»?",
    choices:["Пока подделываешь имя, даже полиция мира и сила закона на 100% никогда не узнают","Совершенно неверно. Любая связь через сеть всегда оставляет след «IP-адреса (адреса)», который точно записывает, с какой машины в каком доме отправлены данные, поэтому преступника можно вычислить и поймать в любой момент","Когда наступит ночь, написанные данные автоматически исчезнут","Если писать буквы задом наперёд, никто никогда не узнает"],
    answerIndex:1,
    explanation:"Поздравляем! С этим ты достигаешь рубежа «100-го вопроса» всей серии. Тот, кто под «анонимным именем» буянит оскорблениями или угрозами в мире сети, думает, что носит плащ-невидимку, но это великое заблуждение. Дорога интернета (провайдер) автоматически на 100% точно, 24 часа в сутки, записывает абсолютный электронный след (лог, IP-адрес) — «в какой час, минуту и секунду и с машины по какому адресу на Земле пакет был отправлен». Если ты напишешь ранящие кого-то слова, то через суд и юридические процедуры твоё настоящее имя и дом будут вычислены одним ударом, и ты заплатишь наихудший итог: тяжёлый штраф или арест. Знай скрытое устройство сети и используй ответственные слова." },
  { id:101, topic:"Приёмы поиска", emoji:"⌨️",
    question:"Используя поисковую систему интернета, какой способ поиска самый эффективный, чтобы за мгновение найти верные научные данные, которые тебе действительно нужны, не отвлекаясь на бесполезный информационный мусор?",
    choices:["Ввести свои эмоциональные предложения как есть, длинно, вроде «живот болит, помогите, что делать»","Выбрать 2 или 3 ключевых слова сути того, что хочешь узнать, и сочетать их, разделив «пробелами», как «как устроен желудок  желудочный сок  кислотность»","Многократно вводить лишь одну цифру снова и снова в строке поиска","Закрыть глаза и наугад колотить по множеству кнопок клавиатуры"],
    answerIndex:1,
    explanation:"Алгоритмическая мудрость, чтобы быстрее всего вытащить нужный алмаз из моря информации, называется «поиском по ключевым словам (И-поиск)». Если искать эмоциональными словами вроде «помогите», вываливается поток столь же эмоциональных, шумных фальшивых дневников, и твоё время теряется впустую. Выстроив в ряд несколько «конкретных имён собственных и научных слов» того, что хочешь узнать, разделив пробелами, поисковая система чисто отсеивает и доставляет только «продвинутые настоящие книги и данные, содержащие все слова сразу». Овладение тем, как искать информацию (навыком поиска), ведёт к росту продуктивности, рождающему многократно больше времени жизни." },
  { id:102, topic:"Экономика внимания", emoji:"🎰",
    question:"Многие соцсети и игры делают так, что новая информация появляется, когда ты тянешь экран вниз, или пытаются заставить тебя много раз нажимать кнопку «нравится (оценка)». В чём наибольшая скрытая цель (хитрость) такого дизайна экрана?",
    choices:["Это доброе волонтёрство, чтобы ускорить ум детей и сделать их гениями","Она психологически изучает баг человеческого мозга, что чувствует удовольствие при встрече со случайной удачей (выброс дофамина), делает тебя неспособным оторваться от приложения и крадёт твоё «драгоценное время жизни (внимание)» ради рекламной прибыли (ловушка поведенческой экономики)","Чтобы автоматически чистить грязь с экрана смартфона","Особой цели нет; это форма, сделанная наугад"],
    answerIndex:1,
    explanation:"Это ужасающая ловушка «экономики внимания (бизнеса по краже времени)», расставленная сегодняшними гигантскими ИТ-компаниями. Как у казиношного игрового автомата, когда человеческий мозг сталкивается с состоянием «прокручу экран — не знаю, какая забавная история (удача) выйдет дальше», в мозге фонтаном выбрасывается вещество удовольствия дофамин, и ты уже не можешь остановиться силой собственной воли. Не успеешь заметить — впустую потратил часы, у тебя отнята сила на учёбу и труд, и твоя жизнь эксплуатируется ради их прибыли. Спокойно разгляди «психологическую хитрость, делающую тебя зависимым» за экраном и верни себе в руки контроль над временем." },
  { id:103, topic:"Компьютерный вирус", emoji:"🦠",
    question:"В интернете, если неосторожно открыть вложение письма от незнакомца или подозрительный файл со словами «скачай это и играй в платные игры бесплатно», что вторгается в машину и ломает её?",
    choices:["Микробы железной ржавчины","«Компьютерный вирус (вредонос)», который сзади захватывает систему машины или берёт в заложники данные внутри и уничтожает их","Магия, от которой переливается вода","Просто обычный текст, ни с чем не связанный"],
    answerIndex:1,
    explanation:"Море интернета густо усыпано вредоносными программами — «компьютерными вирусами (вредоносами)», сделанными, чтобы ломать чужие смартфоны и ПК или красть пароли и данные о деньгах внутри. Они надевают маску сладких слов вроде «это бесплатно» или «приложение, дающее большие деньги», и поджидают, чтобы заставить тебя своей рукой нажать кнопку разрешения загрузки. В миг, когда ты по неосторожности откроешь его, твоя машина захватывается вирусом и превращается в «курьера вируса (зомби-ПК)», который сам рассылает вирусные пакеты на машины друзей. Строго соблюдай железное правило обороны: никогда не открывать файл, источник которого не на 100% надёжен." },
  { id:104, topic:"Двухфакторность", emoji:"📲",
    question:"При входе в важный аккаунт, после ввода заранее заданного пароля, как называется механизм безопасности, который дополнительно заставляет ввести «одноразовый цифровой шифр (код подтверждения)», пришедший на твой смартфон?",
    choices:["Бартер","Двухфакторная аутентификация (двухэтапная проверка / 2FA)","Запрет монополии","Удаление алгоритма"],
    answerIndex:1,
    explanation:"Сильнейшая система безопасности, разом поднимающая защищённость аккаунта более чем в десять тысяч раз, — это «двухфакторная аутентификация». Даже если созданный тобой пароль (фактор памяти) украден вором, пытающимся войти с другого конца света, при наличии этого механизма вор войти не сможет. Ведь дверь дома не откроется, пока не введёшь секретное число, которое в реальном времени приходит на твой собственный настоящий смартфон (фактор владения) и исчезает за мгновение. Для важных аккаунтов имей мудрость всегда настраивать эту вторую линию обороны." },
  { id:105, topic:"Перегрузка информацией", emoji:"🌀",
    question:"Каждый день с телевизора и из интернета бесчисленное множество информации, текста и видео обрушивается на смартфон. Как способ использования головы, чтобы мудро выжить в этом огромном море информации (перегрузке информацией), какое суждение верное?",
    choices:["Следует вложить в голову каждое поступающее видео и статью, не упуская ни слова, все 24 часа","Прими, что в информации 99% шума (бесполезного мусора и слухов), мудро выбирай только алмазоподобные «высокополезные (полезные) данные», что делают тебя счастливым, полностью игнорируй остальной шум и береги выносливость мозга","Громко писать гневные комментарии на всю информацию","Верить всей сетевой информации и каждый день паниковать"],
    answerIndex:1,
    explanation:"Современное общество — эпоха «перегрузки информацией», где переполняют данные, далеко превосходящие предел способности человеческого мозга обрабатывать. Если эмоционально вовлекаться в каждую поступающую новость и слух — «ой, что делать!» «этот тип плохой!» — драгоценная энергия мозга (рассудительность лобной доли) в мгновение опустошается, и не остаётся сил на важные решения собственной жизни. Мудрость холодно вычитать «сигнал (по-настоящему нужное знание)» из «шума (чужих жалоб и дезинформации)» и пропускать шум, даже не вводя его в поле зрения, максимизирует здоровье и независимость твоего мозга." },
  { id:106, topic:"Открытый код", emoji:"🐧",
    question:"Как называется чудесный механизм сотрудничества, когда гениальные программисты по всему миру не прячут исходный код (чертёж программы) полезного приложения, сделанного с усердием, а «публикуют его бесплатно для всех» в интернете, чтобы все могли свободно дорабатывать и улучшать его?",
    choices:["Монопольная система","Открытый код (OSS)","Инфляция","Сокрытие закрытого ключа"],
    answerIndex:1,
    explanation:"Чем одной компании втайне прятать чертёж, чтобы строить его (закрытый код), полностью опубликовать чертёж десяткам тысяч программистов мира, которые находят баги и улучшают его вместе, завершает куда более быструю и чудесную систему. Этот механизм называют «открытым кодом». Системы, что движут интернетом по всему миру (как Linux), удобные инструменты разработки и даже базовая технология этого приложения во многом сделаны человеческой «мудростью сотрудничества», каковой и является открытый код. Делиться и развивать ради богатства целого, а не загребать собственную выгоду, — самая прекрасная культура взаимопомощи цифрового мира." },
  { id:107, topic:"Облако", emoji:"☁️",
    question:"Вместо хранения фото и данных внутри своего смартфона или ПК, как называется механизм безопасно доверять данные «сверхгигантским дата-центрам мира (сейфам)» в глубине дороги интернета, чтобы извлекать их откуда угодно?",
    choices:["Дырка розетки","Облако (облачное хранилище)","Коробка для бартера","Аналоговая пластинка"],
    answerIndex:1,
    explanation:"Если держать данные только внутри своей машины (локально), в миг, когда ты уронишь и сломаешь или потеряешь её, данные-сокровище тоже теряются за мгновение. Но с технологией «облака» (что означает облака) твои данные безопасно хранятся через интернет на серверах прочнейших и идеально резервированных гигантских дата-центров мира. Благодаря этому, даже если твой смартфон сломается и ты купишь новый, достаточно войти с новой машины, чтобы за одну секунду извлечь исходные данные точь-в-точь как были, как ни в чём не бывало. Это цифровая инфраструктура, что превосходит физические пределы данных и делает сохранность твоего имущества идеальной." },
  { id:108, topic:"Машинное обучение и ИИ", emoji:"🤖",
    question:"В последние годы, подражая устройству человеческого мозга и давая прочитать огромные объёмы данных (опыт), «ИИ (искусственный интеллект)» автоматически учится различать фото и составлять предложения. Как называется эта технология?",
    choices:["Машинное обучение (глубокое обучение)","Применение задачи о посадке деревьев","Аналоговое вычисление","Автоматическая генерация паролей"],
    answerIndex:0,
    explanation:"Механизм, благодаря которому ИИ умнеет, называется «машинным обучением». Вместо того чтобы человек писал команды строка за строкой, ИИ сам внимательно наблюдает (учится на) миллионах «данных фото собак», автоматически вычислением находит общие для собак признаки (узоры формы ушей и носа) и, увидев новое фото, может самостоятельно судить «это собака с вероятностью 99%». Зная этот механизм ИИ, вместо того чтобы бояться или поклоняться ИИ как магическому богу, ты можешь обрести взрослый взгляд — спокойно овладевать им как «самым удобным топором следующего поколения (инструментом)» для максимальной эффективности дел с помощью данных." },
  { id:109, topic:"Кибербуллинг", emoji:"🗯️",
    question:"В интернет- или игровых чатах, почему травля (кибербуллинг) — писать грубые слова (сдохни, дурак, исчезни и т. п.) друзьям или незнакомцам, или распространять ложные плохие слухи — это преступление, столь же худшее, как насилие в реальном мире?",
    choices:["От большого количества текста забивается линия сети и тяжелеет","Лезвие слов наносит серьёзную глубокую рану мозгу и сердцу (психике) другого и обладает чудовищной реальной разрушительной силой, способной ввергнуть в отчаяние и отнять жизнь","Сетевой текст пачкает стекло экрана","Особой причины нет; в сети можно говорить что угодно"],
    answerIndex:1,
    explanation:"Мысль «раз видимая кровь не течёт, сказать гадость текстом — пустяк» — медицински и научно полная грубая ошибка. У мозга человека, которого с экрана продолжают обливать грубыми словами и упорными словами травли, «та же самая область мозга (нейросеть боли)» неистово кричит и ранится, как при свирепом физическом нападении (ударе кулаком или ногой), и его клетки умирают. Слова порой становятся опасным оружием, что рвёт в клочья жизнь человека глубже и дольше, чем телесное насилие. Платить уважение сердцу и правам других и пускать в круговорот энергию добрых слов — абсолютная мораль сетевого общества." },
  { id:110, topic:"Куки", emoji:"🍪",
    question:"Когда ты просматриваешь любой сайт в интернете (покупки, чтение и т. п.) со смартфона или ПК, всегда втайне за кулисами между машинами обмениваются «данными записи следов и предпочтений твоей машины». Как это называется?",
    choices:["Ключ от пароля","Куки (Cookie)","Шифрованный текст","Знак переработки"],
    answerIndex:1,
    explanation:"Есть информационный механизм под названием «куки (Cookie)» — то же имя, что у печенья. Это как «маленькая бумажка с текстовой заметкой», которую владелец сайта втайне оставляет внутри браузера твоей машины. Благодаря этой бумажке ты получаешь удобную пользу (плюсы): на сайт, куда вошёл однажды, на следующий день автоматически входишь без ввода ID, а товары, положенные в корзину, не исчезают. Но одновременно поведенческие данные о том, «какие сайты ты смотришь и чем интересуешься», за кулисами утекают компаниям, и тебя делают мишенью рекламы — это риск приватности (минусы). Правильно пойми и свет, и тень этого механизма." },
  { id:111, topic:"Условия использования", emoji:"📜",
    question:"Начиная новое приложение или игру, в чём экономический риск того, чтобы разом нажать кнопку «согласен», не прочитав «условия использования», написанные мельчайшим шрифтом и пространно появляющиеся в начале экрана?",
    choices:["Если не прочесть условия, цвет экрана смартфона весь станет розовым","Внутри документа есть упущение (баг), и на деле, даже если тебя заставили заключить невыгодное обещание (договор) о том, что «компания может свободно продавать по всему миру твои личные данные и фото ради прибыли», ты, не заметив, отдаёшь собственные права человека","Есть закон, что тем, кто не читает условия, нельзя повышать уровень в игре","В миг запуска приложения всё электричество в доме гаснет"],
    answerIndex:1,
    explanation:"Как ты учил в экономике Пакета 2, нажать кнопку «согласен» имеет ровно тот же вес, что «поставить печать и подпись на бумажном договоре» во взрослом мире — строгое юридическое действие. Среди плохих приложений всегда есть такие, что нарочно вставляют пугающее условие глубоко в мелкий шрифт, который никто не читает: «мы высосем все контакты и фотоданные твоего смартфона и используем свободно». Даже если трудно прочесть всё идеально, имей мудрую осторожность хотя бы использовать глаза мудрости и пальцем пролистать, чтобы проверить важные комнаты, где написаны «обращение с личными данными» и «правила денег (платежей)»." },
  { id:112, topic:"Мир 0 и 1", emoji:"🔢",
    question:"В человеческом мире много букв, сложных цветов и красивой музыки, но в голове компьютера (в цифре) вся информация выражается и вычисляется лишь «сочетанием двух чисел». Что это за два числа?",
    choices:["1 и 2","0 и 1 (двоичная / основание 2)","9 и 10","100 и 1000"],
    answerIndex:1,
    explanation:"Изнанка электронной схемы компьютера на деле может различать лишь два состояния: «состояние, где ток течёт (ON / 1)» и «где не течёт (OFF / 0)». Механизм, что заменяет все буквы, цвета фото и колебания музыки числовыми данными и обрабатывает их лишь этим сочетанием переключателей 0 и 1, называется «цифрой (основание 2 / двоичная система)». Как бы сложной ни выглядела система большого города или игра высокого качества, если нырнуть до самого сущностного основания, всё построено лишь из этой «простой, красивой гармонии (логики) 0 и 1». Знать корень механизма — первый шаг к господству над цифрой." },
  { id:113, topic:"Кликбейт", emoji:"🖱️",
    question:"Как называется вредоносная интернет-статья, что нарочно ставит крайний, интригующий заголовок — вроде «Шок! Герой того суперпопулярного аниме на самом деле был тяжело ранен и исчез!?» — чтобы заставить тебя нажать ссылку?",
    choices:["Статья с открытым кодом","Кликбейт (статья-наживка / клик-мошенничество)","Статья проверки фактов","Уведомление о резервной копии"],
    answerIndex:1,
    explanation:"Заголовок-наживку, что взламывает человеческие эмоции любопытства и шока — «ой, интересно!» «правда ли!?» — чтобы любой ценой заставить тебя «кликнуть» ссылку, называют «кликбейтом». Их цель ни на миллиметр не в том, чтобы донести до тебя верную правду. Их единственная цель — заставить нажать ссылку, показать рекламу своего сайта на твоём экране и получить рекламную прибыль (деньги). Открыв содержимое, обычно находишь лишь одну строку нелепой лжи или какой-то пустячный слух. Увидев крайний заголовок, холодно разгляди логическими глазами «ага, это пытается подцепить меня и заработать денег» и нажми тормоз мудрости — игнорировать." },
  { id:114, topic:"Призовое мошенничество", emoji:"🎉",
    question:"Ты открываешь интернет, и крупными буквами появляется: «Поздравляем! Вы — счастливый победитель, выбранный из 1 000 000 человек по всему миру! Нажмите здесь сейчас и получите новейший роскошный смартфон бесплатно (0 монет)!» Как ты рассудишь?",
    choices:["Это самая большая удача в мире, поэтому я с великой радостью нажимаю кнопку и ввожу адрес доставки и домашний телефон","Я логически вижу, что это на 100% поддельная преступная ловушка (призовое мошенничество), нажимаю крестик на экране и полностью игнорирую. Ведь в этом мире абсолютно нет доброго незнакомца, который без причины бесплатно дарит роскошную вещь незнакомому ребёнку","Чтобы похвастаться друзьям, я фотографирую этот экран и выкладываю в соцсеть","Чтобы проверить, правда ли можно получить, я касаюсь экрана 10 000 раз подряд"],
    answerIndex:1,
    explanation:"Это классическая и наихудшая ловушка «призового мошенничества», в которую попадают миллионы людей по всему миру. Нажав кнопку, ты слышишь что-то вроде «оплатите всего 100 монет за доставку картой», и в миг, когда ты вводишь это, все зашифрованные данные кредитной карты твоего дома крадутся, и сотни тысяч монет тратятся без разрешения, разоряя твой дом. Как ты учил в экономике Пакета 2 и риск-менеджменте Пакета 3, бесплатное богатство, внезапно падающее с неба там, где нет ни труда, ни равноценного обмена, на 100% абсолютно невозможно. Смети ловушку, что метит в твоё «чувство жадности», логикой науки." },
  { id:115, topic:"Дипфейк", emoji:"🎬",
    question:"По телевизору или в интернете ты видишь новостное [видео], где известный лидер громко говорит: «Отныне считайте всех друзей ворами и отнимайте у них всю еду!» Можно ли верить, что это видео на 100% настоящее?",
    choices:["Есть доказательство — видео, что я вижу глазами, и голос, что я слышу ушами, поэтому это на 100% настоящее","Ни в коем случае нельзя верить как есть. С нынешней технологией ИИ (дипфейк) можно за одну секунду подделать поддельное «видео лица» или «лживый голос», неотличимые от настоящих, поэтому следует проверить факт (факты) за видео","Если человек в видео в крутой одежде, надо верить","Правильно — швырнуть в видео камень и разбить его"],
    answerIndex:1,
    explanation:"Давным-давно «видео или фото, увиденные глазами», были абсолютным доказательством истины. Но в современную эпоху, где технология ИИ взрывообразно развилась, злоупотребляют технологией «дипфейк», что синтезирует поддельные видео и аудио, выглядящие точь-в-точь как настоящие. Случаи, когда плохие политики или мошенники, чтобы погубить достоинство соперника или развязать войну, заставляют в видео произнести «лживую реплику, которой не говорили», точь-в-точь как настоящий человек, чтобы обмануть людей, часты по всему миру. Именно потому, что мы живём в эпоху, где даже видео, увиденное глазами, уже не на 100% истина, совершенно необходим продвинутый «щит информации» — проверять официальные данные и доказательства нескольких сайтов проверки фактов, прежде чем эмоционально гневаться." },
  { id:116, topic:"Авторское право", emoji:"🎨",
    question:"Копировать без разрешения красивую музыку, замечательный код программы или любимый рисунок или текст (защищённое произведение), сделанные кем-то с усердием, лгать, что это твоё, и распространять в сети (например, распространять пиратские копии), — почему это преступление, которое нельзя совершать?",
    choices:["От копирования чужой вещи твой смартфон становится вдвое тяжелее","Это лишает уважения создателей, что производят новую замечательную ценность (мудрость), и разрушает систему мотивации, по которой они получают справедливое вознаграждение за труд, останавливая эволюцию всего общества (нарушение авторского права)","Копирование без разрешения делает весь цвет текста прозрачным","Есть закон, что все могут свободно использовать всё, что делают друзья"],
    answerIndex:1,
    explanation:"Оригинальное достояние мудрости, что кто-то производит, используя голову, называют «интеллектуальной собственностью», а правовой щит, защищающий её, — «авторским правом». Если бы ты сделал мир (беззаконные джунгли, где сильный пожирает слабого), где любой мог бы свободно красть и бесплатно распространять без разрешения чужое, создатели, что отчаянно месяцами исследовали, чтобы сделать замечательные приложения и музыку, не смогли бы есть, и никто больше не делал бы новых удобных инструментов. Чтобы не остановить эстафету эволюции общества, справедливо защищай ценность чужой мудрости и плати уважение. Это доброе обещание всех в мудром информационном обществе." },
  { id:117, topic:"Отладка", emoji:"🐞",
    question:"Собирая код программы, ты столкнулся с ошибкой (багом), и приложение не работает как задумано. В этот миг какова самая логичная, быстрая и мудрая процедура «найти причину (отладки)»?",
    choices:["Крича «не работает! ужас!», я мгновенно стираю весь код и переписываю с нуля наугад","Я спокойно читаю текст сообщения об ошибке и, тестируя по клетке по порядку, нахожу «до куда программа работает нормально и с какой одной строки (каких данных) начинается противоречие» (отладка)","Я сильно бью кулаком по экрану компьютера","Я гневаюсь и виню окружающих, утверждая, что кто-то переписал код без разрешения"],
    answerIndex:1,
    explanation:"Действие найти и починить баг (ошибку) программы называют «отладкой». Когда возникает баг, тот, кто паникует, решает «всё пропало», полагается на чутьё и переписывает наугад, сам порождает ещё больше новых багов и бесконечно тратит время. Система компьютера очень честна и движется лишь по правилам причины и следствия. Появление бага значит, что всегда где-то в одном месте спрятано «логическое противоречие (странная команда)» как отклонение в один миллиметр. Полностью выровнять эмоции и, разделяя данные по одному, найти границу — «до сюда OK, отсюда NG» — это лучший способ использования головы, мышление вычитающей логики, полезное не только в программировании, но и в решении всех бед жизни." },
  { id:118, topic:"Синий свет и сон", emoji:"🛌",
    question:"Ночью, в тёмной комнате в постели, привычка пристально смотреть на экран смартфона (синий свет) прямо до самого сна разрушает в руины выносливость твоего тела и мозга. В чём научная причина?",
    choices:["Из экрана смартфона вылетают невидимые маленькие жучки и съедают твой мозг","Сильный синий свет с экрана раздражает нервы в глубине твоих глаз и заставляет мозг сильно ошибиться (баг) — «сейчас полдень, ясное яркое небо!» — поэтому он полностью останавливает выделение важного гормона для сна (мелатонина)","Смотреть на экран ночью — машина смартфона ржавеет и ломается","Есть правило, что если смотреть на свет в темноте, все ногти на ногах отвалятся"],
    answerIndex:1,
    explanation:"В глубине человеческого мозга есть механизм часов (циркадный ритм), что управляет температурой тела и сном, говоря «сейчас утро, сейчас ночь», в такт 24-часовому календарю одного оборота Земли. Люди в древности чувствовали ночь, видя красноту солнечного света, и начинали готовиться ко сну. Но «синий свет» с экрана смартфона имеет ровно ту же длину волны, что и полуденный солнечный свет. Если купаться в этом свете с близкого расстояния в ночной тьме, датчик часов твоего мозга выдаёт яростный баг — «ах! сейчас полдень! надо вставать!» — и полностью выключает «переключатель глубокого сна» для чистки мозга и восстановления тела. В итоге усталость не снимается, даже когда ты спишь, на следующий день голова мутная и раздражённая, и твоя собственная энергия независимости резко падает. Закрывать экран за час до сна — научная мудрость ежедневного ухода, чтобы не сломать твой драгоценный мозг, твой инструмент высшего секрета." },
  { id:119, topic:"Распределённая сеть", emoji:"🕸️",
    question:"По сравнению с «централизованным» механизмом, что собирает все данные и власть мира в один большой гигантский компьютер (сервер) для управления, в чём наибольшее достоинство с точки зрения обороны механизма (P2P / распределённой сети), где малые компьютеры мира соединяются, деля данные как равные?",
    choices:["Сделать один центральный сервер больше — выглядит круче и кажется прочнее","Поскольку нет центрального короля, даже если плохой вор или диктатор взорвёт или захватит одну базу, на 100% абсолютно невозможно разрушить всю систему или полностью стереть данные — у неё непобедимая стойкость (устойчивость)","Децентрализация делает потребление электричества всегда нулевым","Меньшие машины могут печатать на купюрах большие числа"],
    answerIndex:1,
    explanation:"Это величайшее доказательство мудрости «децентрализации», основы Web3 и сетей следующего поколения. Централизованная система в миг, когда самый большой центральный компьютер (король) повержен, или плохой диктатор удобно переписывает (фальсифицирует) данные внутри, или линию выдёргивают, видит, как механизм всего связанного общества полностью рушится за мгновение и гибнет целиком. Но в сети «равный с равным (P2P)» или распределённой, где все держат понемногу одни и те же данные на равных и следят друг за другом, даже если 1 или 10 мест разрушены врагом, оставшиеся десятки тысяч компьютеров продолжают бодро работать, поэтому система продолжает автономно крутиться, не останавливаясь ни на миллиметр. Это логика сильнейшего механизма: не давать одному сильному правителю держать жизнь и имущество и поддерживать мир в безопасности равным доверием всех." },
  { id:120, topic:"Итог цифры", emoji:"💡",
    question:"Последний вопрос тебе, прошедшему весь Пакет 4 этого «Wise World 3». Какова [истинная наибольшая цель] правильного изучения сущностного устройства интернета, цифровой технологии и программирования?",
    choices:["Стать хакером, ломать чужие ПК и кичиться","Научно понять холодный логический механизм (правила) за магическим инструментом технологии, идеально защитить собственный кошелёк и здоровье мозга от ложной информации и расставленных ловушек зависимости, использовать мудрость для всех и своей рукой спроектировать и создать «добрый, прочный децентрализованный мир», где каждый может жить свободно и независимо, не будучи обманутым","Бесконечно копить очки опыта онлайн-игр и закончить жизнь, не ступив ногой из дома","Хвастать рекордом из всех верных чисел и командовать другими, чтобы подчинялись"],
    answerIndex:1,
    explanation:"Замечательно! С этим все 30 вопросов Пакета 4 идеально завершены. Компьютеры и интернет — не просто игры или игрушки для убийства времени. Это сложнейшие джунгли современной эпохи, густо уставленные пугающими ловушками, чтобы бесконечно высасывать время, деньги и права человека на личные данные из «людей без знаний», что не умеют ими пользоваться, и господствовать над ними, как над рабами. Но теперь, когда ты обрёл в этом пакете передовой информационный компас «алгоритм, шифрование, логика децентрализации, проверка фактов», никогда больше твой мозг не будет взломан мошенниками и уловками ИИ, таящимися за экраном. Вместо того чтобы стать «рабом на стороне используемого» технологией, полностью овладей сутью механизма и стань «господином на стороне использующего (создателем)», что делает мир лучше. И, используя замечательные программы и свет верной информации, что ты создаёшь, соедини товарищей по всему миру в суровых условиях и оставь будущему человечества добрую автономную экономическую сферу и механизм заботы, что не сдаётся центральному контролю. Весь мир от сердца празднует и болеет за успех непобедимого цифрового интеллекта, зажжённого в твоём мозге!" },
  { id:121, topic:"Биоразнообразие", emoji:"🦋",
    question:"Какова главная научная причина, по которой нельзя доводить до вымирания множество видов живых существ в лесах и морях (биоразнообразие) лишь ради удобства людей?",
    choices:["Потому что, если видов существ станет меньше, в книжках с картинками будет меньше страниц и станет грустно","Потому что природа — это единая «экосистема», в которой все живые существа поддерживают друг друга, как сложная сеть, и стоит исчезнуть одной детали, как всё рушится, словно домино, пока и люди не смогут жить","Потому что существа, вымерев, на следующий день превращаются в космическую пыль","Особой причины нет; это просто правило защиты животных"],
    answerIndex:1,
    explanation:"Все живые существа на Земле связаны, как точные шестерёнки часов: не только через то, кто кого ест (пищевую цепь), но и потому, что растения создают кислород, насекомые переносят пыльцу, а бактерии возвращают отходы в почву. Это называют «экосистемой». Если из-за людского чрезмерного промысла или застройки вымирает какое-то существо, сотни других жизней, что на него опирались, гибнут разом, и в конце концов разрушаются даже питьевая вода, еда и воздух людей, так что человечество губит само себя. Защищать разнообразие — это безусловный долг, чтобы система жизнеобеспечения Земли работала исправно." },
  { id:122, topic:"Глобальное потепление", emoji:"🌡️",
    question:"Воздух вокруг Земли в самый раз удерживает тепло Солнца, словно комната, и хранит тепло, в котором могут жить существа (парниковый эффект). Какая опасность скрыта за этим чудесным устройством?",
    choices:["Что, если воздух слишком нагреется, Земля превратится в квадрат","Что, если слишком много жечь уголь и нефть и «углекислого газа» в воздухе станет чересчур много, удерживающий тепло барьер станет слишком толстым и температура всей Земли аномально поднимется (глобальное потепление)","Что, если воздух станет горячим, цифры на банкнотах исчезнут сами собой","Опасности нет вовсе; чем теплее, тем всегда безопаснее"],
    answerIndex:1,
    explanation:"Земля сохраняет температуру, при которой могут жить существа, а не замерзает, потому что парниковые газы вроде углекислого газа в воздухе работают как одеяло. Но из-за того, что люди ради промышленности продолжали жечь огромные количества ископаемого топлива, это одеяло стало неестественно толстым, и тепло всей Земли уже не может уйти в космос. Это и есть «глобальное потепление». Стоит температуре подняться всего на несколько градусов, как толстый лёд, покрывающий сушу Антарктиды и Гренландии, тает и стекает в море, да и сама морская вода нагревается и расширяется, отчего уровень моря поднимается. Многие острова и города затопляются, страшные засухи и огромные тайфуны становятся вероятнее, и всему человечеству грозит голод. Нужна мудрость беречь равновесие воздуха." },
  { id:123, topic:"Ископаемое топливо", emoji:"⛽",
    question:"Какова главная слабость, как ресурса Земли, ископаемого топлива вроде «угля» и «нефти», которые люди используют с давних времён?",
    choices:["Что, даже сгорая, оно совсем не даёт света и всё остаётся тёмным","Что, будучи останками древних существ, копившимися под землёй сотни миллионов лет, при дальнейшем использовании людьми «когда-нибудь оно непременно иссякнет и исчезнет (ограниченный ресурс)»","Что оно слишком тяжёлое, чтобы перевозить его на кораблях или машинах","Что от использования ископаемого топлива вся вода превращается в сок"],
    answerIndex:1,
    explanation:"Это важное правило о смене энергии (энергетическом переходе). Ископаемое топливо вроде нефти и угля — это банки энергии, которые Земля чудом накопила за головокружительно долгий срок в сотни миллионов лет. Но стоит их использовать и сжечь — они уже никогда не вернутся. Если продолжать потреблять их с нынешней безумной скоростью человечества, однажды объём, который можно добыть, иссякнет, и общество, целиком зависевшее от них, погрузится в великий хаос. Именно поэтому мудрость великого перехода к «возобновляемой энергии», что снова и снова рождается силой природы — светом Солнца, ветром, силой воды, — совершенно необходима для будущего выживания всего человечества." },
  { id:124, topic:"Городские рудники", emoji:"♻️",
    question:"Вместо того чтобы закапывать как мусор сломанные машины, железные банки и пластик из дома, мы мелко переплавляем их и многократно используем заново как «новые ресурсы». В чём подлинная ценность такой переработки для защиты Земли?",
    choices:["В том, что переработка делает мусорное ведро более красивым на вид","В том, что больше не нужно ради новых металлов и материалов всё глубже вгрызаться в красивые горы и леса Земли и разрушать природу (риск добычи) (городские рудники)","В том, что при переплавке мусора оттуда сами выскакивают слитки золота","В том, что переработка — это просто игра ради увеличения числа банкнот"],
    answerIndex:1,
    explanation:"Минеральные ресурсы Земли — железо, медь, редкие металлы — тоже ограничены и имеют пределы. Чтобы добыть новые, люди и сейчас самосвалами разрушают ценные первозданные леса Земли и роют глубокие ямы, раздирая природу в клочья. Но если мы не выбрасываем уже использованные вещи, а собираем их и перерабатываем, то мусор, уже имеющийся в наших городах, перерождается в прекрасные новые ресурсы. Это называют «городскими рудниками». Это мудрость умелого управления материалами ради построения устойчивого общества, которое заставляет уже имеющееся богатство кружиться по кругу и служить долго, не раня Землю ещё больше." },
  { id:125, topic:"Водные ресурсы", emoji:"💧",
    question:"Землю называют «планетой воды», настолько она покрыта водой, но «пресная вода», которую мы, люди, можем пить, составляет лишь около скольких процентов от всей воды на Земле?",
    choices:["Около 90% от всего — это вкусная пресная вода","Около 97,5% воды Земли — это солёная морская вода, а легкодоступная пресная вода в реках и озёрах, которой могут пользоваться люди, составляет лишь около «0,01% от всего»","Вода бесконечна, поэтому процент посчитать нельзя","Вся вода Земли — пресная"],
    answerIndex:1,
    explanation:"Это холодный, суровый факт (данные) о водных ресурсах. Прекрасная голубая вода Земли, видимая из космоса, в большинстве своём (около 97,5%) — это «солёная морская вода», от которой, выпей её просто так, наступит обезвоживание. Та малость пресной воды, что остаётся, почти вся заморожена в виде льда на Северном полюсе, Южном полюсе и высоких горах, так что нежная вода, которой мы, люди, можем сразу воспользоваться из рек и озёр, — это чудесно малое количество: «около 0,01% от всей воды Земли». Когда немногие люди присваивают, загрязняют или растрачивают эту драгоценнейшую пресную воду — это значит собственными руками перерезать спасательный канат для всех. Будем твёрдо следовать мудрости делиться водой и хранить её чистой." },
  { id:126, topic:"Микропластик", emoji:"🧴",
    question:"Когда пластиковый мусор выбрасывают в море или реки, свет Солнца и волны дробят его на крошечные кусочки — «микропластик». Почему это возвращается и вредит человеческому телу?",
    choices:["Потому что, если микропластик попадёт в глаза, зрение вдруг улучшится","Потому что планктон и рыбы в море поедают мелкие, никогда не исчезающие кусочки пластика, и в итоге «когда человек съедает этих рыб, вредный яд накапливается в его внутренних органах и вызывает болезнь» (биоусиление)","Потому что от поедания пластика тело превращается в робота","Потому что вся вода застывает и превращается в лёд"],
    answerIndex:1,
    explanation:"Пластик — это материал, созданный человеческой химией, с особым свойством: «сила природы почти не может его разложить, и он не возвращается в почву». Мусор, утёкший в море, на вид может казаться раздробленным на крошечные кусочки и исчезнувшим, но он очень долго продолжает дрейфовать в океане в виде «микропластика» размером меньше 5 миллиметров. Ещё страшнее то, что эти мелкие кусочки обладают свойством, как магнит, притягивать к своей поверхности вредные химические вещества (токсины) из моря и концентрировать их. Маленькая рыба съедает их, большая рыба съедает маленькую, и наконец «человек» на вершине пищевой цепи съедает её, так что ком яда, словно бумеранг, накапливается в телах наших собственных детей (биоусиление). В мире всё связано." },
  { id:127, topic:"Тропический лес", emoji:"🌳",
    question:"Почему огромные леса вроде тропического леса Южной Америки (Амазонии), называемые «лёгкими Земли», так бережно охраняют по всему миру?",
    choices:["Потому что форма леса в точности похожа на настоящий человеческий орган — лёгкое","Потому что он вдыхает огромные количества углекислого газа, перегревающего Землю, и хранит его в телах деревьев (хранилище углерода), выделяет много водяного пара, регулируя дождь и климат мира, и является сокровищницей жизни, где обитает великое множество живых существ Земли","Потому что в лесу инопланетяне спрятали тайную базу","Потому что, если срубить много деревьев, земля станет лёгкой и Землю унесёт в космос"],
    answerIndex:1,
    explanation:"Тропические леса вроде Амазонии издавна зовут ласковым прозвищем «лёгкие Земли». Однако их по-настоящему важнейшая роль на деле вовсе не в том, чтобы создавать кислород. Растения леса и впрямь создают кислород через фотосинтез, но существа и микробы самого леса при дыхании расходуют почти столько же, так что выяснено: чистое количество кислорода, отправляемого в атмосферу, близко к нулю (бóльшую часть кислорода, которым мы дышим, создал крошечный растительный планктон океана за долгое время). Так почему же тропический лес столь важен? Потому что он — «хранилище углерода», вдыхающее огромные количества перегревающего Землю углекислого газа и хранящее его в телах деревьев; «гигантский кондиционер Земли», выделяющий много водяного пара, чтобы регулировать дождь и климат по всему миру; и «сокровищница жизни», где обитает великое множество видов существ. Если срубить этот лес ради сиюминутных денег, накопленный углерод хлынет в воздух, потепление рванёт вперёд, и климат мира и множество жизней будут разрушены. Разрушение природы в одном краю, обойдя круг, расстраивает климат даже у тебя, живущего в далёкой стране. Будем смотреть глобально, защищая всю Землю как единую систему." },
  { id:128, topic:"Права человека", emoji:"🗽",
    question:"Как называется безусловное право, которым обладает каждый человек в мире — независимо от страны рождения, цвета кожи, языка, мальчик он или девочка — жить по-человечески, с добротой и в безопасности?",
    choices:["Право ходить за покупками","Основные права человека (права человека)","Право приказывать другим и заставлять их подчиняться","Право играть в игры 24 часа подряд"],
    answerIndex:1,
    explanation:"Величайшая основа общественной мудрости — это «основные права человека». В мире далёкого прошлого считалось само собой разумеющимся, что сильные короли и те, кто держал оружие, могли отнимать жизнь и свободу у слабых, как у рабов. Человечество училось на бесчисленных трагических войнах и страданиях, и в 1948 году ООН приняла «Всеобщую декларацию прав человека». Это величайшее доброе обещание человечества: «Все люди равны от рождения, и ничью свободу, ничью жизнь никто другой не вправе несправедливо ранить». Знание прав человека становится величайшей силой, чтобы защищать себя и оберегать достоинство других." },
  { id:129, topic:"Образование девочек", emoji:"👧",
    question:"Почему защита права девочек (женщин) ходить в школу и получать «образование (учёбу)» наравне с мальчиками делает всё общество гораздо богаче?",
    choices:["Потому что, если девочки учатся, число распускающихся цветов удваивается","Потому что, когда женщины, составляющие половину населения, обладают верными знаниями науки, медицины и экономики, смертность детей от болезней сильно снижается, а сила создавать полезные новые рабочие места и мудрость удваивается","Потому что девочки аккуратнее считают цифры на банкнотах","Особой причины нет; это просто правило для вида"],
    answerIndex:1,
    explanation:"В некоторых краях мира и поныне девочек лишают образования из-за ошибочного предрассудка, что «девочке незачем ходить в школу, а нужно трудиться дома». Но исследования и данные о развитии показывают, что чем больше страна продвигает образование женщин (гендерное равенство), тем быстрее она выбирается из бедности и развивается. Если мать обладает знаниями о гигиене и медицине, она может уберечь младенца от болезней; если женщины обладают деловой мудростью, без конца рождаются новые добрые экономические круги. Связывать чьи-то возможности по признаку пола — это на деле тормоз для развития всего общества." },
  { id:130, topic:"Детский труд", emoji:"⛏️",
    question:"В некоторых бедных краях мира маленьких детей не пускают в школу и заставляют целыми днями работать на опасных рудниках и полях — это «детский труд». В чём подлинная причина того, что это абсолютно непростительно?",
    choices:["Потому что, если дети работают, взрослые лишаются работы и попадают в беду","Потому что, когда в детстве отнимают важнейшую «возможность учиться (образование)», то и взрослыми они не понимают букв, счёта и научной мудрости и никогда не могут вырваться из «порочного круга», где их всю жизнь обманывают дурные люди и эксплуатируют в бедности","Потому что, если дети что-то делают, форма всех инструментов становится круглой","Потому что закон гласит, что детям можно только играть на улице"],
    answerIndex:1,
    explanation:"Подлинный ужас детского труда — не только в сиюминутной усталости тела. Худшее преступление в том, что он с корнем вырывает будущие возможности этого ребёнка (крылья мудрости) и передаёт цепи бедности и следующему поколению. Ребёнка, который не умеет читать и считать, взрослым заставляют подписывать невыгодные договоры, ему не платят справедливой зарплаты и всю жизнь заставляют работать ради чужой выгоды, как раба. Образование — это сильнейший инструмент, чтобы разрубить эти жалкие цепи бедности. Защита права детей всего мира учиться напрямую связана с устранением таких несправедливых систем." },
  { id:131, topic:"Война и мир", emoji:"🕊️",
    question:"Когда страны или люди сталкиваются с разногласиями во мнениях или борьбой за ресурсы, какова главная причина решать это через переговоры (дипломатию), а не худшим выбором — «войной (насилием)»?",
    choices:["Потому что от войны пачкается одежда и стирка становится тяжёлой","Потому что победа или поражение силой ничуть не доказывает, «чья сторона права»; она даёт лишь печальный итог — «чья сторона способна уничтожить больше невинных жизней», глупый выбор, при котором все терпят огромный убыток","Потому что при переговорах легче громко кричать","Потому что война автоматически уменьшает размер Земли вдвое"],
    answerIndex:1,
    explanation:"Суть войны (насилия) — это полное поражение логики. Сколько бы ни нападали друг на друга новейшим оружием, исходная проблема (нехватка воды или граница земли) ничуть не решается. После остаются лишь смерть бесчисленных людей, разрушенные города и худший долг — яростная «цепь ненависти», не угасающая поколениями. У человечества есть слова и мудрость для того, чтобы взвешивать положение и выгоды-потери каждой стороны и выдумывать «правило дележа (дипломатию)», с которым согласны обе стороны. Упорство продолжать диалог, не сдаваясь, — это и есть мудрость по-настоящему сильных." },
  { id:132, topic:"Беженцы", emoji:"🧳",
    question:"Как называют людей, которые потеряли дом и едва спаслись бегством в другую безопасную страну, потому что их родина была втянута в войну или поражена большим бедствием?",
    choices:["Туристы","Беженцы (перемещённые лица)","Шайка воров","Инопланетяне"],
    answerIndex:1,
    explanation:"Изгнанные из дома «беженцы» вовсе не пришли в другую страну по своей охоте. Ещё вчера, совсем как ты, это были обычные люди, что ели дома, ходили в школу и жили спокойно, с улыбкой. Из-за внезапного насилия или бедствия в одно мгновение у них отняли всё имущество и покой, и им не оставалось ничего, кроме как бежать, чтобы выжить. Общество, что закрывает границы, отвергает их и бросает, — это холодный мир, своими руками нарушающий обещание прав человека. Мудрость сопереживания — представить чужую боль как свою и в беде по-доброму протянуть убежище в духе «сегодня тебе, завтра мне» — становится крепкой линией обороны мира на планете." },
  { id:133, topic:"Ненасилие", emoji:"☮️",
    question:"Почему способ борьбы под названием «ненасилие» — которым великие вожди прошлого (такие как Махатма Ганди) сопротивлялись несправедливым правителям, не беря оружия, — был гораздо мощнее, чем применение насилия?",
    choices:["Потому что, сэкономив деньги на оружии, они смогли купить много вкусных сладостей","Потому что, сами не применяя насилия, они ясно доказали перед глазами всего мира и несправедливую жестокость правителя, и «справедливость собственного требования прав человека», и привлекли несметное число союзников","Потому что, провозглашая ненасилие, тело становится твёрдым, как железо","Потому что они просто прятались в углу комнаты, чтобы их не били"],
    answerIndex:1,
    explanation:"Когда отвечаешь на насилие насилием, со стороны это выглядит лишь «дракой плохих людей», и настоящая проблема скрывается. Но сколько бы их ни били, как бы несправедливо ни арестовывали, действие ненасилия (гражданского неповиновения) — тихо стоять на своём, ни разу не взяв оружия, и говорить «мы лишь требуем своих законных прав как людей» — вбивает прямо в сердца людей всего мира тот факт, что «неправ именно нападающий правитель». Эта сила справедливости движет сердцами мощнее любой пушки и в конце концов становится огромной волной доверия, что движет государствами, пока наконец не меняет саму систему несправедливой власти." },
  { id:134, topic:"Задачи без границ", emoji:"🌍",
    question:"Почему такие задачи, как изменение климата, происходящее по всей Земле, или вирусные болезни, распространяющиеся по миру (пандемии), нельзя решить, если меры принимает лишь одна страна?",
    choices:["Потому что с одной лишь страной в зале совещаний остаются лишние стулья и становится грустно","Потому что для воздуха природы, волн моря и невидимых вирусов проведённая людьми линия под названием «граница (рубеж между странами)» совсем не действует, и вся Земля связана, как единая комната","Потому что, если страна маленькая, форма всех лекарств становится круглой","Потому что другие страны сердятся и приходят мешать мерам"],
    answerIndex:1,
    explanation:"Это физическая реальность Земли. Сколько бы людей ни чертили на карте линии со словами «отсюда начинается наша страна», загрязнённый где-то воздух смешивается с небом всего мира, а вирус, возникший в другой стране, садится на самолёт и в одно мгновение втекает в твой город. Экологические проблемы и инфекционные болезни нельзя полностью преградить, даже если одна страна потратит деньги на возведение барьера. Лишь система «сотрудничества в мировом масштабе (глобального управления)» — где все страны Земли разом откладывают свои эгоистичные интересы (эго), делятся одними и теми же данными и объединяют силы, держа одни и те же обещания (международные договоры), — есть путь спасти человечество от великой беды." },
  { id:135, topic:"Культурное разнообразие", emoji:"🗿",
    question:"В чём великая потеря для всего человечества, когда исчезают самобытные языки и культуры (разнообразие), которые коренные народы и меньшинства каждой земли хранили тысячи лет?",
    choices:["В том, что больше нельзя увидеть яркие наряды на праздниках, и это скучно","Потому что навсегда теряется ценная человеческая мудрость, которой современная наука ещё не знает, — «мудрость о растениях, что становятся лекарством» и «знание наблюдения за природой, чтобы пережить климатические кризисы», нужные для жизни на той земле","Потому что, если языков станет меньше, словари станут меньше и дешевле","Потери нет вовсе; удобнее объединить все культуры мира в одну"],
    answerIndex:1,
    explanation:"Разнообразные культуры и языки мира — это не просто развлечение или различия во внешности. Это «собрание самого отточенного знания о выживании», которое каждый народ выстраивал, тщательно наблюдая природу, чтобы продолжать жизнь сотнями поколений на своих суровых землях (в джунглях, пустыне, землях лютого холода). Подсказка к лекарству, которого современная медицина ещё не нашла, на самом деле очень часто дремлет в мудрости о целебных травах, унаследованной коренными жителями джунглей. Растоптать это как «старое и отсталое» и стереть так же расточительно, как собственными руками разорвать и выбросить ценный «козырь», которым человечество могло бы решить будущие кризисы." },
  { id:136, topic:"Справедливая торговля", emoji:"🍫",
    question:"Викторина о покупках. Когда ты покупаешь в магазине шоколад или кофе, какая «тьма экономики (несправедливость)» может скрываться за товаром, цена которого слишком низкая?",
    choices:["Что в дешёвом товаре внутри нет настоящего шоколада","Что он может быть кристаллом слёз, сделанным фермерами далёких бедных стран, которых крупные компании несправедливо заставляют работать за гроши, а дети не могут ходить в школу и принуждены трудиться (эксплуатация)","Что от дешёвых сладостей твой вес вдруг утраивается","Что, если цена низкая, цвет банкнот становится цветом плесени"],
    answerIndex:1,
    explanation:"За покупками, на которых мы радуемся «ух ты, дёшево и выгодно!», стоит реальность, где дети того же возраста, живущие на другом краю Земли, целыми днями в поту вынуждены собирать какао-бобы и страдают, почти не получая зарплаты. Систему, что несправедливо высасывает прибыль из людей в слабом положении, называют «эксплуатацией». Чтобы не быть к ней причастным, обрети мудрость разумно выбирать товары «справедливой торговли», которые специальная организация удостоверила как обеспечивающие справедливую оплату тем, кто их сделал. То, как ты тратишь деньги, становится голосом, делающим мир лучше." },
  { id:137, topic:"Трагедия общин", emoji:"🐑",
    question:"На общем деревенском пастбище, которым пользуются все, все проигнорировали правила и выпасли огромное число овец со словами «хочу нажиться только сам», и в итоге трава была вся съедена, а овцы у всех остались голодными. Как называется эта знаменитая ловушка экономики?",
    choices:["Победа бартера","Трагедия общин (трагедия общего достояния)","Взрыв производительности","Завершение инфляции"],
    answerIndex:1,
    explanation:"Замечательное достояние, которым все вместе пользуются, — вроде речной воды, морской рыбы и воздуха Земли — называют «общинами (общими ресурсами)». Когда все действуют по желанию «максимизировать собственную выгоду», ресурс расходуется быстрее, чем успевает восстанавливаться, и в итоге все рушатся вместе. Это называют «трагедией общин». Чтобы предотвратить эту трагедию, нельзя обойтись без общественной мудрости, при которой не сильный диктатор присваивает ресурс, а все на равных заключают твёрдые правила (соглашение) — «больше этого не использовать, не загрязнять» — и управляют им, приглядывая друг за другом." },
  { id:138, topic:"Севооборот", emoji:"🌾",
    question:"Если в поле каждый год сажать на одной и той же земле в точности одно и то же растение (например, пшеницу), не давая ей отдыха (монокультура, бессменный посев), почему через несколько лет это терпит крах, земля скудеет так, что урожай не растёт?",
    choices:["Потому что от вечного вида одного и того же растения почве становится скучно и она засыпает","Потому что в почве истощаются лишь определённые питательные вещества (минералы), а определённые болезни и вредители, любящие это растение, взрывообразно размножаются, пока почва не оскудеет и не истощится (вред бессменного посева)","Потому что растениям одиноко и они все ночью убегают куда-то","Потому что температура почвы автоматически поднимается до 100 градусов и становится опасной"],
    answerIndex:1,
    explanation:"В почве великой природы бесчисленные невидимые микробы (бактерии и грибы) держат разнообразное равновесие и взрыхляют почву, делая её пушистой. Но когда ради людской выгоды сажают только одно и то же, потому что «пшеница приносит деньги» (монокультура), разнообразие экосистемы почвы рушится, и она становится местом, где легко размножаются определённые вредные плесени и вредители. Это называют «вредом бессменного посева». Мудрые люди прошлого изобрели мудрость «севооборота» — каждый год менять то, что сажают: в этот год бобы, на следующий — картофель, затем кормовые травы — и давать почве отдохнуть несколько лет, и так сохраняли силу почвы сотни лет. Подстраиваться под цикл природы — это мудрость, чтобы продолжать долго." },
  { id:139, topic:"Круговорот углерода", emoji:"🔄",
    question:"Вещество под названием «углерод» на Земле без устали кружит между телами живых существ, воздухом и морем. Какова подлинная причина того, что люди сильно нарушили равновесие этого круговорота углерода?",
    choices:["Потому что люди слишком много дышат и съедают весь кислород в воздухе","Потому что уголь и нефть (комья углерода), которые древняя Земля заперла глубоко под землёй за сотни миллионов лет, люди всего за несколько сотен лет разом выкопали и сожгли, вернув их в воздух","Потому что, когда едет много машин, углерод из земли улетает в космос","Потому что свет Солнца меняет цвет углерода на чёрный"],
    answerIndex:1,
    explanation:"Общее количество углерода на Земле почти постоянно, но равновесие того, «где он находится», — ключ к жизни. Углерод в деревьях леса и телах существ возвращается в почву, когда они умирают, кружа в добром равновесии. Но величайшая проблема в том, что люди после промышленной революции разом вскрыли гигантскую капсулу времени из углерода — ископаемое топливо (окаменелости древних существ), которое Земля бережно заперла глубоко под землёй за сотни миллионов лет, чтобы никогда не выпускать на поверхность, — и сожгли её. Из-за этого деяния, полностью обогнавшего скорость, с какой природа медленно его кружила, углекислого газа в воздухе резко стало больше, и это вызывает глобальное потепление. Причину создали человеческое невежество и алчность." },
  { id:140, topic:"Энергосбережение", emoji:"🔌",
    question:"В чём самый важный для всей Земли смысл того, чтобы почаще выключать свет в комнате и сокращать ненужное потребление энергии (энергосбережение)?",
    choices:["В том, что от выключенного света в комнате темнеет и привидениям легче появляться","В том, что бóльшая часть электричества, используемого в мире, и поныне создаётся сжиганием ископаемого топлива, поэтому сокращение пустой траты электричества напрямую сокращает газы потепления и останавливает разрушение природы","В том, что энергосбережение автоматически увеличивает твой смартфон","В том, что государство выдаёт тебе банкноту с надписью «молодец»"],
    answerIndex:1,
    explanation:"Электричество, текущее из розетки, не бьёт само откуда-то ключом. За ним множество тепловых электростанций создают электричество, сжигая драгоценные нефть и уголь Земли и при этом выпуская дым и углекислый газ (больше половины электричества мира и поныне получают из такого ископаемого топлива). Иными словами, пока ты оставляешь свет в комнате включённым, где-то на Земле расходуются ресурсы и загрязняется воздух. Всякое использование энергии связано с вычитанием из ресурсов всей Земли. Бережливая мудрость срезать лишнее — это достойный поступок, доступный каждому, понемногу продлевающий жизнь Земли." },
  { id:141, topic:"Компостирование", emoji:"🍂",
    question:"Вместо того чтобы выбрасывать в сжигаемый мусор овощные очистки и остатки еды (пищевые отходы) от готовки, ты подмешиваешь их в почву и даёшь силе воздуха и микробов медленно разложить их (компостирование). Во что они перерождаются?",
    choices:["Мусор расплавляется в кашицу и превращается в чистое пластиковое ведро","Силой микробов мусор разлагается на питательные вещества и перерождается в «лучшую пушистую почву (компост)», которая растит крепкими и здоровыми следующие растения и вкусные овощи","Если положить пищевые отходы в почву, оттуда сами начинают бить ключом банкноты","Мусор прямо превращается в каменную глыбу и становится фундаментом для постройки дома"],
    answerIndex:1,
    explanation:"В великой природе изначально не существует такого понятия, как «мусор». Опавшие в лесу листья и помёт животных — всё становится пищей бесчисленных микробов (бактерий и грибов) в почве, со временем разлагается и перерождается в питательные вещества (компост), чтобы следующей весной росли новые деревья. Мудрость внести этот безотходный великий круговорот природы в человеческую жизнь называют «компостированием (изготовлением компоста)». Ответственно возвращать то, что ты выпустил, в семя следующей жизни — это основная доброта, чтобы не превращать Землю в свалку." },
  { id:142, topic:"Искоренение болезней", emoji:"🩺",
    question:"В прошлом страшная вирусная болезнь «оспа» унесла жизни множества людей (особенно детей) по всему миру, а в 1980 году была [полностью стёрта из природного мира Земли (искоренение)]. Какова причина этого великого подвига в истории человечества?",
    choices:["Потому что, когда все в мире каждый день громко молились, вирус испугался и сбежал в космос","Потому что страны всего мира, врачи и ООН (ВОЗ) объединили силы поверх границ и доставили «вакцину (прививку)» каждому человеку на Земле без исключения, не оставив вирусу места для бегства (победа человеческого сотрудничества)","Потому что вирусу надоел вкус людей и он исчез сам","Потому что температура Земли резко упала и все вирусы замёрзли насмерть"],
    answerIndex:1,
    explanation:"Это одна из величайших побед в истории человечества, добытая мудростью и сотрудничеством. «Оспа» была очень страшной болезнью, что покрывала всё тело сыпью и убивала с высокой долей и детей, и взрослых. Чтобы победить этого врага, человечество преодолело противостояние между странами (холодную войну) и сотрудничало, годами продолжая невероятную операцию по доставке вакцин людям всего мира. Вирус, поскольку все, к кому он пытался перейти, имели «щит иммунитета», лишился места для размножения и наконец полностью исчез из природного мира (это называют «искоренением»). Это мощное доказательство истории: если люди по-настоящему делятся мудростью и объединяются, они могут переписать даже судьбу, кажущуюся безнадёжной, и спасти мир." },
  { id:143, topic:"Свобода слова", emoji:"🗣️",
    question:"Почему право, по которому любой в обществе может свободно высказывать словом и письмом мнения, что считает верными, и идеи, как сделать общество лучше, не будучи никем запуган (свобода слова), необходимо для защиты страны?",
    choices:["Потому что, когда все громко выкрикивают свои имена, в городе становится оживлённо и можно устроить праздник","Потому что, если этой свободы нет и можно высказывать лишь мнение некоего сильного властителя, никто не сможет затормозить тяжкие ошибки общества, и вся страна понесётся вразнос","Потому что от свободы писать число страниц в тетради растёт без конца","Потому что от свободы выражения цифры на банкнотах автоматически становятся больше"],
    answerIndex:1,
    explanation:"Как мы уже учили в наборе об информации, чтобы держать безопасность всего общества (устойчивость) на высоте, нельзя обойтись без тормоза (свободы слова), которым люди могут возвысить голос и сказать «этот приказ или правило странны, это опасно». Если общество наполнится людьми, что из страха не могут сказать правду сильному властителю и способны лишь поддакивать даже лжи, то, когда вождь нажмёт кнопку ошибочной войны или разрушения среды, никто не сможет его остановить и все граждане будут втянуты. Демократическое устройство, в котором самые разные люди свободно и на равных обмениваются мнениями и каждый раз могут исправлять ошибки, — это и есть мудрость, что держит общество в наибольшей безопасности и надолго." },
  { id:144, topic:"Город, стойкий к бедствиям", emoji:"🏙️",
    question:"Чтобы построить «город, стойкий к бедствиям (город предотвращения бедствий)», где люди могут долго жить в безопасности и без травм даже на суровой земле, где легко случаются крупные землетрясения и огромные наводнения, какова важнейшая мудрость проектирования?",
    choices:["Покрыть все стены зданий слитками золота, чтобы они выглядели как роскошнейший замок","Хорошо изучить записи о крупных бедствиях прошлого (исторические данные) и заранее спроектировать «гибкую конструкцию здания (сейсмоизоляцию)», пропускающую сквозь себя страшную энергию природы, и каналы, по которым вода безопасно уходит (идея смягчения бедствий)","Каждый день сажать вокруг дома много красивых цветов, чтобы бедствия не приходили","Убедить себя, что что бы ни случилось, всё будет хорошо, и не принимать никаких мер"],
    answerIndex:1,
    explanation:"Против огромной разрушительной силы природы проект, который лишь строит твёрдые, прочные стены и пытается силой встретить её в лоб, однажды непременно будет в одно мгновение разбит превосходящей его энергией природы, вызвав большую беду. Подлинная мудрость управления кризисом — взять за учебник данные о бедствиях за сотни лет и заранее встроить во весь город системы «смягчения бедствий» и «сейсмоизоляции», которые «умело пропускают сквозь себя силу природы (тяготение и поток воды)». Сообразительность проектировать системы, делающие законы природы своим союзником, а не идущие против них, защищает жизнь дорогой семьи на поколения." },
  { id:145, topic:"Научный метод", emoji:"🔬",
    question:"Когда встречаешь странное событие или невиданную болезнь, как называют «способ работы головы», при котором перестаёшь слепо верить, что «так сказал кто-то важный» или «это древнее предание», и сам наблюдаешь и ставишь опыты, чтобы установить достоверные факты?",
    choices:["Магическое мышление","Научный способ мышления (научный метод, критическое мышление)","Просто своевольная догадка","Автоматическое удаление паролей"],
    answerIndex:1,
    explanation:"Самый сильный способ работы головы, что спас человечество от страха тьмы и суеверий и развил столь удобные медицину и технологии, — это «научный метод». Это способ мышления (критическое мышление), при котором тебя не уносит чьими-то эмоциональными словами или слухами, а ты раз останавливаешься собственной головой, спрашивая «правда ли это? если поставить опыт, можно ли много раз воспроизвести тот же результат?», и накапливаешь доказательства (свидетельства). Человек, у кого в голове работает этот научный двигатель, способен остро разглядеть сладкие слова мошенников и подозрительную ложную информацию, таящуюся в мире. Это лучший инструмент мышления, чтобы стать хозяином собственной мудрости." },
  { id:146, topic:"Справедливость между поколениями", emoji:"👶",
    question:"Богатая среда Земли, наши удобные инструменты и чудесные медицинские знания — собственность не только нас, живущих сейчас. В каком состоянии мы должны передать это детям будущего, ещё не рождённым?",
    choices:["Истратить всё в нашем поколении, вырубить все деревья и оставить им всё в мусоре","Бережно принять эстафету истории, что передали нам предки, отполировать её своей мудростью ещё больше до «Земли чище, чем вчера, и безопаснее, чем вчера» и передать следующему поколению (справедливость между поколениями)","Разрушить все здания, вернуться к жизни древней первобытной эпохи и передать это","Поскольку будущее меня не касается, оставить всё как есть, ни о чём не думая"],
    answerIndex:1,
    explanation:"Подлинная причина, по которой у людей есть мудрость и они могут учить историю, — в том, чтобы передать эту «эстафету мудрости (справедливость между поколениями)» в будущее. То, что мы сейчас можем пить безопасную воду, лечиться лекарствами, заболев, и читать книги, чтобы учиться, — оттого, что сотни поколений предков давнего прошлого не истратили в своём поколении алмазы мудрости, найденные ими через множество неудач и усилий, а бережно сберегли и донесли до нас. Теперь наш черёд, как хранителей Земли, передать эту эстафету маленьким жизням будущего в ещё более прекрасном виде. Будем смотреть широко, заботясь о жизнях будущего." },
  { id:147, topic:"Альтруизм", emoji:"🙋",
    question:"Идущий перед тобой незнакомец уронил тяжёлую ношу и попал в беду. Этот человек родился в другой стране и говорит на другом языке, и нет никакой возможности, что он отплатит тебе. Какое самое мудрое действие тебе стоит совершить?",
    choices:["Поскольку чужие дела меня не касаются, со смехом не обращать внимания и пройти мимо","Даже без отплаты помощь человеку в беде увеличивает «накопление доверия всего общества (социальный капитал)», а это строит безопасный мир, где кто-то по-доброму поможет тебе, когда ты однажды попадёшь в беду, поэтому охотно протянуть руку","Отнять у этого человека ношу и убежать","Положить вокруг ноши много больших камней, чтобы мешать"],
    answerIndex:1,
    explanation:"Это сущностное свидетельство о доброте, не ищущей отплаты (альтруистичном поведении). Человек силой лишь одного себя не может пережить беды природы и общества. Доброе действие, которым ты сегодня помог чужому горю, понемногу повышает доверие всего общества (социальный капитал) — ощущение, что «этот мир добрый и безопасный». В обществе, где это накопление доверия скопилось вдоволь, если ты однажды упадёшь на самое дно одиночества или тяжёлой болезни, незнакомый кто-то протянет тебе руку. Пускать доброту по кругу становится и величайшей безопасностью для тебя самого." },
  { id:148, topic:"Открытая наука", emoji:"🔓",
    question:"Кто-то изобрёл «чертёж новой чистой энергии, что спасёт Землю». Что спасает человечество быстрее: хранить эту мудрость в тайне лишь для себя или сделать её «бесплатной и открытой» для учёных всего мира?",
    choices:["Хранить в тайне, чтобы самому стать богатейшим человеком в мире и кичиться, — вот что быстрее очищает Землю","Потому что, сделав её полностью открытой для всего мира (открытая наука), можно соединить мудрость множества исследователей, быстро улучшить и распространить по миру, остановив потепление раньше (сила сотрудничества)","Сложить чертёж в бумажный самолётик и запустить его в сторону моря","Никому не сказав, закопать его глубоко в землю и забыть"],
    answerIndex:1,
    explanation:"Как мы учили об открытом исходном коде (OSS) в наборе об информации, это мудрость «открытой науки», что спасает будущее Земли. Пока один человек прячет чертёж в тайне и пытается нажить состояние, потепление движется, а ущерб ширится, пока острова мира не уйдут под воду. Сердце, что пытается присвоить мудрость, в итоге ведёт к гибели целого. Щедро поделиться своим прекрасным изобретением или идеей ради всех товарищей, плывущих на едином корабле по имени Земля, и синхронизировать силу умов всего мира, чтобы разом решить огромную задачу, — вот предельная сила сотрудничества, которой обладает человечество." },
  { id:149, topic:"Опасность слепого подчинения", emoji:"⛓️",
    question:"Какова скрытая величайшая опасность того, чтобы просто без всяких раздумий продолжать подчиняться (слепое подчинение) — будь то правилам и законам, что кто-то создал, или тому, что говорят взрослые?",
    choices:["Потому что, если продолжать подчиняться, размер твоей обуви вдруг уменьшается и ноги болят","Потому что, если в это правило или приказ закралась ошибка, ранящая права человека, вроде «исключать и травить слабого», а ты ленишься думать сам, то, не заметив, ты сам становишься «виновником» дискриминации или преступления","Потому что есть закон, по которому у серьёзных, послушных людей вся еда становится горькой","Опасности нет вовсе; всегда без раздумий подчиняться тому, что говорят взрослые, — самое безопасное в мире"],
    answerIndex:1,
    explanation:"Многие из самых трагических войн и массовых убийств (резни) в истории затеяли вовсе не злодеи-чудовища от рождения. Их вызвали действия совершенно обычных, серьёзных людей, что со словами «потому что это приказ сверху» или «потому что так делают все» совсем перестали думать своей головой о добре и зле (отказ от мышления). Мыслитель Ханна Арендт назвала это «банальностью зла». Каким бы важным ни был тот, кто создал правило, всегда проверяй глазом собственного разума (критическим мышлением), не ранит ли оно «чью-то жизнь, права человека или доброту», и всегда держи в сердце крепкий щит самостоятельности, способный ясно сказать «НЕТ» тому, что неправильно." },
  { id:150, topic:"Финал трилогии", emoji:"🎓",
    question:"Поздравляем! На этом ты завершил все 150 вопросов серии «Wise World» и все викторины трилогии. Какова была подлинная, окончательная и величайшая цель всей твоей учёбы доныне — об устройстве тела, законах природы, экономике и доверии, управлении кризисами, цифровых технологиях и будущем Земли?",
    choices:["Похвалиться рекордом всех верных ответов, стать величайшим королём мира и заставить слабых подчиняться твоим приказам","Прочно накопить в голове «сильнейший щит по имени мудрость», стать самостоятельным, нигде в мире больше не дать себя обмануть дурной информацией или подчинением, надёжно защищать права человека и жизнь себя и всех товарищей и своими руками создать и оставить «добрую и безопасную экономическую сферу и мир благополучия», что продолжает вращаться ради детей будущего даже после твоего ухода","Поднять уровень в интернет-игре до предела и окончить всю жизнь, не сделав ни шагу из комнаты","Просто посмотреть на экран прохождения и начисто забыть всё, чему учился"],
    answerIndex:1,
    explanation:"По-настоящему поздравляем — большие, большие аплодисменты! От самого первого вопроса, что ты встретил малышом, до вершины этого 150-го вопроса ты разгадал все загадки мудрости, и твой ум уже не проиграет легко ни словам какого-либо мошенника взрослого мира, ни какой-либо затягивающей ловушке, что пытается захватить твой мозг, ни какой-либо цепи, что пытается несправедливо тебя подчинить. «Логика науки, доверие экономики, дальновидность управления кризисами, цифровой щит и широкий взгляд, любящий всю Землю», что ты обрёл в этой трилогии, станут крепчайшим в мире оберегом, что навсегда защищает твою жизнь. И этим зажжённым светом мудрости бережно возьми за руку плачущих вокруг тебя людей и незнакомых товарищей всего мира, что не могут позволить себе даже телефон, и своими руками построй здесь, на этой Земле, добрую экономическую сферу (мягкую экономическую сферу), что не опирается лишь на центральную власть, где никто не голодает и никто не оставлен в стороне. Та надёжная эстафета мудрости, что ты изучил до конца, перепишет грядущий мир так, чтобы он был прекраснее, чем вчера, и станет светом, что бесконечно озаряет путь всех детей будущего. Все в мире от всего сердца болеют за твою грядущую самостоятельность и за полный успех твоего великого путешествия-приключения. По-настоящему, по-настоящему, поздравляем!" }
];
